/* characters q02 (44 mục) — R2.6 bồi tiểu sử Niếp sư muội */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q02"]=window.__LIBQ["pham-nhan-tu-tien"]["q02"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q02"]["characters"]={"updatedAt":"2026-07-05","count":44,"chars":[{"id":"ton-nhi-cau","name":"Tôn nhị cẩu","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tứ bình bang","trangThai":"da-roi"},{"ten":"Hàn Lập (thủ hạ bị khống chế)","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Không rõ — thường nhân/võ lâm","trangThai":"song","blurb":"Nguyên tiểu đầu mục bang Tứ bình bang, quản sự bến đò Tây thành Gia Nguyên Thành ở Lam Châu, dáng gầy gò đầu méo mắt chuột và thông thuộc mọi tin tức lớn nhỏ trong thành. Sau khi mưu cướp Hàn Lập bất thành, hắn đầu hàng và bị ép nuốt Hủ tâm hoàn khống chế, trở thành tai mắt cho Hàn Lập. Về sau được cài làm bang chủ bù nhìn của Tứ bình bang mới rồi được giải trừ độc dược.","vaiTro":"Thủ hạ tai mắt của Hàn Lập; bang chủ bù nhìn Tứ bình bang","tinhCach":"Giỏi nịnh nọt, khéo luồn lách; tham lam, thấy lợi là tính chuyện cướp bóc; biết thời thế, quỳ hàng ngay khi thất thế; thông thạo tin tức khắp thành","tabs":{"diem":[{"text":"Mưu cùng Hắc Hùng cướp tài phú trong bao đồ Hàn Lập, chia chác bốn-sáu","chuong":"@c0101"},{"text":"Đầu hàng sau khi thủ hạ bị Khúc Hồn hạ gục và Hắc Hùng bị giết, bị Hủ tâm hoàn khống chế","chuong":"@c0103"},{"text":"Báo tin xác thực về Thần tiên đại hội của nhóm tu tiên giả tại phụ cận Gia Nguyên Thành","chuong":"@c0119"},{"text":"Nhận Dẫn hồn chung, được cài làm bang chủ bù nhìn để điều khiển Khúc Hồn","chuong":"@c0120"},{"text":"Chính thức lên bang chủ Tứ bình bang mới sau khi Trầm Trọng Sơn và tam đại hộ pháp chết vì Tiêu Hồn Tán","chuong":"@c0122"},{"text":"Được Hàn Lập tặng giải độc đan, giải trừ vĩnh viễn Hủ tâm hoàn trong người","chuong":"@c0125"}],"kinhLich":[{"chuong":100,"importance":"normal","text":"Xuất hiện tại bến đò Gia Nguyên Thành, cùng đám thủ hạ chửi bới đám Hắc hùng mỗi sáng. Chứng kiến Hàn Lập và Khúc Hồn cập bến."},{"bridge":true,"khoang":"c0101–c0102","text":"Nhận ra tài phú lớn trong bao đồ Hàn Lập; hội ý Hắc Hùng chia chác bốn-sáu, sai thủ hạ dẫn Hàn Lập vào hẻm Hắc Thuỷ phục kích."},{"chuong":103,"importance":"normal","tieuDe":"Đầu hàng — bị Hủ tâm hoàn khống chế","text":"Chứng kiến hơn hai mươi thủ hạ bị Khúc Hồn hạ gục và Hắc Hùng bị Hàn Lập đâm chết. Quỳ xin hàng, khoe am hiểu Gia Nguyên Thành. Bị Hàn Lập ép nuốt Hủ tâm hoàn — độc cần giải dược mỗi tháng một lần. Nhận bạc vụn hơn trăm lạng để dọn sạch hiện trường, hẹn sáng hôm sau gặp tại khách sạn."},{"bridge":true,"khoang":"c0104–c0107","text":"Báo cáo tình hình ba đại bang và chi tiết Mặc phủ cho Hàn Lập; nhận túi bạc hào phóng, được giao do thám về Ngô Kiếm Minh."},{"chuong":119,"importance":"normal","tieuDe":"Báo tin Thần tiên đại hội","text":"Mang về tin xác thực: nhóm tu tiên giả sắp họp Thần tiên đại hội tại phụ cận thành Gia Nguyên. Nguồn tin: một cấp cao Tứ bình bang say rượu tiết lộ, lấy từ đầu mục nhỏ tình cờ nghe được khi giả chết bằng Quy tức công. Bang chủ Trầm Trọng Sơn đã ra lệnh cấm truyền."},{"chuong":120,"importance":"major","tieuDe":"Nhận Dẫn hồn chung — được Hàn Lập cài làm bang chủ bù nhìn","text":"Hàn Lập giao Dẫn hồn chung để điều khiển Khúc Hồn; chuông đã được ràng bằng máu khóa (chủ nhân gốc) nên kẻ khác không đoạt được. Nhiệm vụ: thâu tóm Tứ bình bang, thay thế Trầm Trọng Sơn làm bang chủ bù nhìn để Hàn Lập khống chế từ phía sau. Hàn Lập sẽ cho Vân sí điểu theo dõi."},{"chuong":122,"importance":"major","tieuDe":"Chính thức lên bang chủ Tứ bình bang mới","text":"Sau khi Trầm Trọng Sơn và tam đại hộ pháp chết vì Tiêu Hồn Tán, Tôn nhị cẩu chính thức lên làm bang chủ Tứ bình bang theo kế hoạch Hàn Lập."},{"chuong":125,"importance":"major","tieuDe":"Nhận giải độc đan — Hủ tâm hoàn giải trừ vĩnh viễn","text":"Hàn Lập tặng Tôn nhị cẩu giải độc đan giải trừ vĩnh viễn Hủ tâm hoàn trong người; ân-uy cùng ban để đảm bảo lòng trung thành bền vững. Hàn Lập rời Gia Nguyên Thành giao Tứ bình bang lại cho Tôn nhị cẩu tự quản."}],"tuViMoc":[],"nhanMach":[{"ten":"Hắc hùng","tag":"dong-minh","quanHe":"Cựu đồng đảng ở bến đò — nay đã chết"},{"ten":"Hàn Lập","tag":"chu","quanHe":"Chủ nhân — đã giải trừ Hủ tâm hoàn c125, trung thành vì ân-uy"},{"ten":"Tịch Thiết Ngưu","tag":"noi-bo","quanHe":"Phó bang chủ Tứ bình bang do Hàn Lập phong c125"}],"tuiDo":{"phapBao":[{"ten":"Dẫn hồn chung","loai":"pháp bảo — chuông đồng","trangThai":"đang giữ — khống chế Khúc Hồn","moTa":"Hàn Lập giao chuông để Tôn nhị cẩu điều khiển Khúc Hồn trong nhiệm vụ thâu tóm Tứ bình bang. Chuông đã được khóa máu chủ nhân gốc.","nguon":["c0120"]}],"danDuoc":[{"ten":"Hủ tâm hoàn","loai":"độc (đã giải trừ)","trangThai":"đã giải trừ vĩnh viễn c125","moTa":"Bị Hàn Lập ép nuốt tại c103. Giải trừ vĩnh viễn bằng giải độc đan Hàn Lập tặng tại c125.","nguon":["c0103","c0125"]}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0100","c0101","c0102","c0103","c0104","c0105","c0107","c0119","c0120","c0122","c0125"]},{"id":"hac-hung","name":"Hắc hùng","cn":null,"aliases":["Hắc đại hán","Hắc gia"],"gioiTinh":"nam","theLuc":[{"ten":"Thiết chưởng hội","trangThai":"da-roi"}],"canhGioiCaoNhat":"Võ giả phàm — công phu hạng cao thủ hạng ba","trangThai":"tu-vong","blurb":"Tiểu đầu mục bang Thiết chưởng hội trấn giữ bến đò Gia Nguyên Thành, cự hán vai to lưng rộng, da đen xanh. Công phu miễn cưỡng vào hàng cao thủ hạng ba, có nhãn lực tốt nhưng phán đoán sai thân phận đối thủ khi mưu cướp Hàn Lập. Bị Hàn Lập đâm xuyên yết hầu bằng nhuyễn kiếm, chết tại hẻm Hắc Thuỷ.","vaiTro":"Tiểu đầu mục Thiết chưởng hội, bến đò Gia Nguyên Thành","tinhCach":"Tham lam, mưu cướp tài phú người qua đường; nhãn lực tinh tường, nhận ra Khúc Hồn chưa xuất toàn lực; phán đoán sai lầm, đánh giá thấp đối thủ","tabs":{"diem":[{"text":"Xuất hiện tại bến đò Gia Nguyên Thành, chứng kiến Hàn Lập và Khúc Hồn cập bến","chuong":"@c0100"},{"text":"Hội ý Tôn nhị cẩu, bố trí hơn hai mươi thủ hạ phục kích cướp tài phú Hàn Lập tại hẻm Hắc Thuỷ","chuong":"@c0101"},{"text":"Nhãn lực tinh tường, nhận ra Khúc Hồn chưa xuất toàn lực","chuong":"@c0100"},{"text":"Lén áp sát đột kích Hàn Lập nhưng bị đâm xuyên yết hầu, tử vong tại hẻm Hắc Thuỷ","chuong":"@c0103"}],"kinhLich":[{"chuong":100,"importance":"normal","text":"Xuất hiện tại bến đò Gia Nguyên Thành, đứng phía đối diện Tôn nhị cẩu. Chứng kiến Hàn Lập và Khúc Hồn cập bến."},{"bridge":true,"khoang":"c0101–c0102","text":"Hội ý Tôn nhị cẩu mưu cướp tài phú Hàn Lập; bố trí hơn hai mươi thủ hạ phục kích tại hẻm Hắc Thuỷ. Treo thưởng hai mươi lạng mỗi người để kích động thủ hạ vây Khúc Hồn; nhận ra Khúc Hồn chưa xuất toàn lực nên mưu tính bắt cóc Hàn Lập thoát thân."},{"chuong":103,"importance":"major","tieuDe":"Bị Hàn Lập đâm xuyên yết hầu — tử vong","text":"Lén áp sát Hàn Lập từ phía sau định đột kích bắt cóc; Hàn Lập phát giác, dùng thân pháp quỷ dị biến mất rồi lách ra sau lưng. Bị đâm xuyên yết hầu bằng nhuyễn kiếm, chết ngay tại chỗ tại hẻm Hắc Thuỷ."}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn nhị cẩu","tag":"dong-minh","quanHe":"Đồng đảng bến đò — cả hai cùng mưu cướp Hàn Lập"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0100","c0101","c0102","c0103"]},{"id":"nghiem-thi","name":"Nghiêm thị","cn":null,"aliases":["Tứ phu nhân","Tứ sư mẫu"],"gioiTinh":"nu","theLuc":[{"ten":"Kinh Giao hội","trangThai":"lanh-dao"},{"ten":"Mặc phủ","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Nghiêm thị là Tứ phu nhân của Mặc đại phu (Mặc Cư Nhân) và cũng là biểu muội của ông, người được chồng chuyển giao phần lớn quyền lợi Kinh Giao hội trước khi rời đi ẩn cư ở Thải Hà sơn. Sau khi tiếp nhận tín vật xác thực từ Hàn Lập, bà một mình chủ trì hội đang sa sút, dùng mưu kế và các quân bài trong tay để mặc cả điều kiện. Đến mốc mới nhất, bà đã giao Noãn dương bảo ngọc đúng hẹn sau khi Hàn Lập hoàn thành nhiệm vụ ám sát.","vaiTro":"Đại diện Kinh Giao hội; Tứ phu nhân Mặc phủ","tinhCach":"Trầm tĩnh, mưu lược; tâm kế hơn người, biết ẩn nhẫn câu giờ chờ cơ hội; quyết đoán khi đàm phán, dám dùng con tin và uy hiếp làm quân bài","tabs":{"diem":[{"text":"Nhận Văn long giới và khớp hai chiếc nhẫn để xác nhận tín vật thật từ Mặc đại phu","chuong":"@c109"},{"text":"Nắm quyền điều phối nội bộ hội, cử Vương thị ra tuần tra vành đai","chuong":"@c111"},{"text":"Bày kế thiên nhân túy tẩm mê dược trong nến trắng nhằm khống chế Hàn Lập nhưng thất bại","chuong":"@c116"},{"text":"Dùng âm hàn chi độc trong người Hàn Lập làm đòn uy hiếp khi đàm phán","chuong":"@c117"},{"text":"Đưa điều kiện trao đổi Noãn dương bảo ngọc lấy việc tiêu diệt các thế lực đối địch","chuong":"@c118"},{"text":"Giao Noãn dương bảo ngọc đúng hẹn sau khi Hàn Lập ám sát Âu Dương Phi Thiên","chuong":"@c126"}],"kinhLich":[{"chuong":108,"importance":"normal","tieuDe":"Hàn Lập nghe lén","text":"Hàn Lập đột nhập Mặc phủ, nghe lén Nghiêm thị và con gái Mặc Thải Hoàn bàn về Ám Đà suy yếu và kẻ giả mạo họ Ngô. Xác nhận bà biết rõ họ Ngô là giả mạo, đang câu giờ vì thế lực kẻ địch quá lớn."},{"chuong":109,"importance":"normal","tieuDe":"Tiếp nhận tín vật và thư Mặc đại phu","text":"Nhận Văn long giới Hàn Lập ném vào phòng; khớp hai chiếc nhẫn xác nhận tín vật thật. Nghe Hàn Lập tự xưng đệ tử Mặc đại phu, chào 'Tứ sư mẫu'. Đọc kỹ thư, cau mày ưu tư — sai Mặc Thải Hoàn đi gọi các phu nhân khác tới."},{"chuong":110,"importance":"normal","tieuDe":"Hỏi gốc tích sư đồ","text":"Hỏi Hàn Lập vì sao Mặc đại phu thu làm đồ đệ. Tỏ thái độ ai oán bất mãn khi nghe chồng ẩn cư Thải Hà sơn suốt tám năm; đa nghi, nhận định Hàn Lập đang giữ bí mật."},{"chuong":111,"importance":"minor","text":"Cử Vương thị ra ngoài tuần tra vành đai trong khi Hàn Lập ở Mặc phủ — cho thấy bà nắm quyền điều phối nội bộ an ninh."},{"chuong":115,"importance":"normal","tieuDe":"Đối mặt Hàn Lập mặc áo tang — bị dò xét bằng linh thức","text":"Gặp Hàn Lập cùng các phu nhân khác trong phòng; mặc áo tang trắng. Bị Hàn Lập dùng linh thức quét toàn không gian trước khi hắn vào."},{"chuong":116,"importance":"normal","tieuDe":"Kế thiên nhân túy thất bại","text":"Tiết lộ mê dược thiên nhân túy tẩm trong nến trắng — tưởng Hàn Lập cũng bị ảnh hưởng; Hàn Lập phá bại. Thừa nhận Gia Nguyên Thành có nhiều người biết tu tiên giả tồn tại; xác nhận Mặc đại phu từng thấy tu tiên giả tranh đấu."},{"chuong":117,"importance":"major","tieuDe":"Đàm phán — dùng âm hàn chi độc làm quân bài","text":"Nâng cây thoa dưới búi tóc, bình tĩnh lại, dùng âm hàn chi độc trong người Hàn Lập làm đòn uy hiếp. Nghe Hàn Lập kể lại toàn bộ chân tướng Mặc đại phu và Dư Tử Đồng. Lão luyện đổ hết tội lỗi lên Dư Tử Đồng để giữ thể diện phu quân. Từ chối giao Noãn dương bảo ngọc — lấy lý do Mặc phủ nguy cơ diệt môn cần ngoại lực."},{"chuong":118,"importance":"major","tieuDe":"Đưa điều kiện — uy hiếp hủy bảo ngọc","text":"Đặt điều kiện trao đổi: Hàn Lập tiêu diệt Ngũ Sắc môn VÀ Độc Phách sơn trang; đổi lại nhận Noãn dương bảo ngọc. Uy hiếp: nếu dùng vũ lực, người tâm phúc sẽ hủy bảo ngọc. Nhiều dã tâm, không chịu bỏ quyền lực Kinh Giao hội."},{"chuong":119,"importance":"normal","tieuDe":"Thận trọng, xin thương lượng trước khi trả lời","text":"Sau khi Hàn Lập đưa điều kiện diệt một bang (không phải cả hai), thận trọng xin được để tỷ muội bàn bạc rồi trả lời vào sáng mai."},{"chuong":122,"importance":"normal","tieuDe":"Ba nghĩa nữ ra mắt Hàn Lập","text":"Hàn Lập đến Mặc phủ sau khi trừ xong Tứ bình bang cũ; gặp ba nghĩa nữ của Mặc đại phu gồm Mặc Ngọc Châu, Mặc Thải Hoàn, Mặc Phượng Vũ — được gọi là 'Mặc thị tam kiều'."},{"chuong":123,"importance":"major","tieuDe":"Chấp nhận điều kiện mới — nuốt thuốc con tin","text":"Đồng ý điều kiện Hàn Lập đặt lại: chỉ diệt trang chủ Độc Bá sơn trang Âu Dương Phi Thiên (thầy của Ngô Kiếm Minh), đổi lấy Noãn dương bảo ngọc. Một mình nuốt thuốc con tin hóa học của Hàn Lập thay cho các con gái, thể hiện bản lĩnh che chắn cho con.; Tiết lộ toàn bộ bí ẩn cục diện Lam Châu cho Hàn Lập: kẻ giả mạo 'họ Ngô' (Ngô Kiếm Minh) chính là đệ tử thứ bảy được sủng ái của Âu Dương Phi Thiên — trang chủ Độc Bá sơn trang ngoài hiệu 'Nộ Sư'. Â…"},{"chuong":126,"importance":"normal","tieuDe":"Giao Noãn dương bảo ngọc (hồi tưởng)","text":"Sau khi Hàn Lập ám sát Âu Dương Phi Thiên thành công, Nghiêm thị giao Noãn dương bảo ngọc đúng hẹn."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"gia-dinh","quanHe":"Chồng (biểu huynh); rời nhà gần mười năm, tình cảm vợ chồng rất sâu"},{"ten":"Mặc Thải Hoàn","tag":"gia-dinh","quanHe":"Con gái ruột"},{"ten":"Mặc Phượng Vũ","tag":"gia-dinh","quanHe":"Nghĩa nữ (con gái nuôi của Mặc đại phu), học y đạo"},{"ten":"Hàn Lập","tag":"khach","quanHe":"Đã giao Noãn dương bảo ngọc sau khi hắn hoàn thành nhiệm vụ diệt Âu Dương Phi Thiên"}],"tuiDo":{"phapBao":[{"ten":"Long văn giới chỉ (một trong cặp)","loai":"tín vật — nhẫn hình rồng","trangThai":"đang đeo","moTa":"Chiếc nhẫn còn lại trong cặp Văn long giới. Khi khớp với chiếc Hàn Lập mang tới thì hoa văn rồng liền mạch hoàn hảo không kẽ hở.","nguon":["c0109"]}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":3,"nguon":["c0104","c0105","c0107","c0108","c0109","c0110","c0111","c0115","c0116","c0117","c0118","c0119","c0122","c0123","c0126"]},{"id":"mac-thai-hoan","name":"Mặc Thải Hoàn","cn":null,"aliases":["Hoàn nhi","Tiểu thư út Mặc phủ"],"gioiTinh":"nu","theLuc":[{"ten":"Mặc phủ","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân (có thể liên quan luyện dược)","trangThai":"song","blurb":"Con gái ruột của Mặc đại phu và Nghiêm thị, khoảng mười lăm mười sáu tuổi, dung mạo giống mẹ bảy tám phần. Tính tình bộc trực, sắc sảo, mang lối xảo trá học từ mẹ; toàn thân tản ra mùi vị tinh linh cổ quái gợi liên quan tới luyện dược. Nàng nhiều lần giao thiệp với Hàn Lập quanh chuyện đan dược và tiền bạc, cho tới khi đuổi theo trách hắn là kẻ lừa gạt lúc hắn rời tiểu lầu.","vaiTro":"Con gái út Mặc phủ — tiểu thư sắc sảo giỏi luyện dược","tinhCach":"Bộc trực, sắc sảo; xảo trá theo lối mẹ Nghiêm thị; thống hận kẻ giả mạo họ Ngô; nhạy bén chuyện tiền bạc đan dược","tabs":{"diem":[{"text":"Nghe lén và bất mãn gay gắt về Ám Đà suy giảm thu nhập cùng kẻ giả mạo họ Ngô","chuong":"@c0108"},{"text":"Gặp Hàn Lập lần đầu khi hắn ném nhẫn vào phòng rồi tự xưng đệ tử","chuong":"@c0109"},{"text":"Đòi Hàn Lập 7-8 nghìn lượng bạc phí đan dược nhưng bị từ chối thẳng","chuong":"@c0112"},{"text":"Nhận viên Oanh Hương Hoàn từ Hàn Lập — đan đỏ tươi thơm ngát vốn điều chế cho Lệ Phi Vũ","chuong":"@c0113"},{"text":"Được nhắc là phiên bản trẻ của Nghiêm thị, tính xảo trá học từ mẹ","chuong":"@c0117"},{"text":"Lần cuối xuất hiện, đuổi theo trách Hàn sư huynh là kẻ lừa gạt, giả mạo khi hắn rời tiểu lầu","chuong":"@c0124"}],"kinhLich":[{"chuong":108,"importance":"normal","tieuDe":"Hàn Lập nghe lén","text":"Trò chuyện với mẹ Nghiêm thị về Ám Đà suy giảm thu nhập và kẻ giả mạo họ Ngô. Bất mãn gay gắt với Ngũ nương độc chiếm Ám Đà và kẻ họ Ngô đang bám đuổi đại tỷ."},{"chuong":109,"importance":"normal","tieuDe":"Gặp Hàn Lập lần đầu","text":"Chứng kiến Hàn Lập ném nhẫn vào phòng rồi gõ cửa tự xưng đệ tử. Cười hé với Hàn Lập trong lúc hắn kể chuyện bái sư, tỏ vẻ hứng thú."},{"chuong":111,"importance":"normal","tieuDe":"Đưa Hàn Lập vào phòng đầu hồi","text":"Theo lệnh Nghiêm thị, đưa Hàn Lập vào căn phòng đầu hồi của Mặc phủ để ổn định trước cuộc bàn bạc."},{"chuong":112,"importance":"minor","text":"Đòi Hàn Lập 7-8 nghìn lượng bạc phí đan dược; Hàn Lập từ chối thẳng."},{"chuong":113,"importance":"normal","tieuDe":"Nhận Oanh Hương Hoàn","text":"Hàn Lập tặng nàng Oanh Hương Hoàn — viên đan đỏ tươi thơm ngát, ban đầu điều chế cho Lệ Phi Vũ. Nàng nghi ngờ đây là xuân dược nhưng chưa dám xác định."},{"chuong":117,"importance":"minor","text":"Nhắc gián tiếp trong lời Hàn Lập: tính xảo trá của nàng học từ Nghiêm thị — nàng là phiên bản trẻ của Nghiêm thị."},{"chuong":"@c0124","importance":"minor","text":"Lần cuối xuất hiện: đuổi theo Hàn Lập khi hắn rời tiểu lầu, trách 'Hàn sư huynh' là kẻ 'lừa gạt / giả mạo', dùng 'một chút đồ vật' (Oanh Hương Hoàn) làm cả nhà nàng 'xoay vòng vòng'; khi Mặc Phượng Vũ xin đi cao ý đạo thì xen vào nói không cần tạ ơn vì vốn là vật của nhà họ, bị Phượng Vũ ngăn lại.","nguonNblm":true}],"tuViMoc":[],"nhanMach":[{"ten":"Nghiêm thị","tag":"gia-dinh","quanHe":"Mẹ ruột"},{"ten":"Mặc Ngọc Châu","tag":"gia-dinh","quanHe":"Đại tỷ — con gái Đại phu nhân Kim thị"},{"ten":"Hàn Lập","tag":"khach","quanHe":"Tự xưng đệ tử Mặc đại phu; tặng Oanh Hương Hoàn"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Oanh Hương Hoàn","loai":"đan hoàn (tặng phẩm)","trangThai":"đã nhận từ Hàn Lập","moTa":"Viên đan đỏ tươi, thơm ngát. Không có công dụng tu luyện; chỉ xua đuổi côn trùng và tỏa hương mê người. Mặc Thải Hoàn ngờ là xuân dược.","nguon":["c0113"]}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0104","c0108","c0109","c0110","c0111","c0112","c0113","c0117"]},{"id":"mac-ngoc-chau","name":"Mặc Ngọc Châu","cn":null,"aliases":["Đại tiểu thư Mặc phủ","Mặc phủ tam kiều (đứng đầu)"],"gioiTinh":"nu","theLuc":[{"ten":"Mặc phủ","trangThai":"hien-tai"},{"ten":"Kinh Giao hội","trangThai":"lien-quan"}],"canhGioiCaoNhat":"Phàm nhân — võ học từ cao thủ Kinh Giao hội","trangThai":"song","blurb":"Mặc Ngọc Châu là đại tiểu thư Mặc phủ, con gái Đại phu nhân Kim thị và Mặc đại phu, nổi danh là mỹ nhân đứng đầu trong 'Mặc phủ tam kiều'. Nàng học võ từ cao thủ Kinh Giao hội và trên danh nghĩa đính hôn với Ngô Kiếm Minh. Tính đến lần xuất hiện gần nhất, nàng bị Tứ nương Nghiêm thị đề nghị gả làm thiếp cho Hàn Lập và giữ im lặng trong cảnh Mặc Phượng Vũ xin đi cầu ý đạo.","vaiTro":"Đại tiểu thư Mặc phủ — mỹ nhân đứng đầu Mặc phủ tam kiều","tinhCach":"Không thích nữ công, ham mê võ nghệ và săn bắn như nam nhi; giữ im lặng dè dặt trước áp lực gia tộc","tabs":{"diem":[{"text":"Mỹ nhân nổi danh nhất Mặc phủ, đính hôn với Ngô Kiếm Minh","chuong":"@c0106"},{"text":"Cưỡi ngựa trở về sau chuyến đi săn, mặc đồ săn đỏ chói đội mũ tím","chuong":"@c0107"},{"text":"Cùng Ngô Kiếm Minh và Yến Ca có mặt trong sân Mặc phủ khi Hàn Lập đi ngang","chuong":"@c0114"},{"text":"Bị Nghiêm thị đề nghị gả làm thiếp cho Hàn Lập, kinh hoàng kêu 'Tứ nương!'","chuong":"@c0123"},{"text":"Lần cuối xuất hiện, im lặng suốt cảnh Mặc Phượng Vũ xin đi cầu ý đạo","chuong":"@c0124"}],"kinhLich":[{"chuong":106,"importance":"normal","tieuDe":"Được nhắc tới","text":"Hàn Lập nghe kể: Mặc Ngọc Châu là mỹ nhân nổi danh nhất Mặc phủ, đính hôn với Ngô Kiếm Minh sau khi hắn đánh bại mười sáu tình địch."},{"chuong":107,"importance":"normal","tieuDe":"Hàn Lập quan sát từ tửu lâu","text":"Cưỡi ngựa trở về sau chuyến đi săn, mặc đồ săn đỏ chói đội mũ tím. Giao ngựa và chiến lợi phẩm cho gia nhân. Nói chuyện thân mật với Ngô Kiếm Minh, ửng đỏ mặt — tình cảm khá sâu. Hàn Lập trên lầu nhìn xuống, lòng xao động."},{"chuong":114,"importance":"minor","text":"Cùng Ngô Kiếm Minh và Yến Ca có mặt trong sân Mặc phủ khi Hàn Lập đi ngang — không biết thân phận thật của Hàn Lập."},{"chuong":"@c0123","importance":"minor","text":"Bị Nghiêm thị (Tứ nương) đề nghị gả làm thiếp cho Hàn Lập cùng hai tỷ muội; kinh hoàng kêu 'Tứ nương!', bị Nghiêm thị quát im. Sau khi Hàn Lập từ chối lời gả con, thái độ với hắn như hòa lại.","nguonNblm":true},{"chuong":"@c0124","importance":"minor","text":"Lần cuối xuất hiện: từ đầu đến cuối im lặng không nói câu nào trong cảnh Mặc Phượng Vũ xin đi cao ý đạo; trước khi rời đi chỉ liếc Hàn Lập một cái khó đoán (cảm kích, ghét, hay cả hai) khiến hắn ngẫm nghĩ rồi bỏ qua.","nguonNblm":true}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"gia-dinh","quanHe":"Cha ruột (đã chết gần hai năm)"},{"ten":"Nghiêm thị","tag":"gia-dinh","quanHe":"Tứ mẫu — người chủ trì Mặc phủ"},{"ten":"Ngô Kiếm Minh","tag":"tinh-cam","quanHe":"Hôn phu danh nghĩa; thực chất là kẻ giả mạo bị Mặc phủ điều tra"},{"ten":"Hàn Lập","tag":"tinh-cam","quanHe":"Con rể tiềm năng theo thư mạo danh của Mặc đại phu"},{"ten":"Yến Ca","tag":"tinh-cam","quanHe":"Đại sư huynh — thầm yêu từ nhỏ, đã tỏ tình nhiều lần bị từ chối"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":3,"nguon":["c0104","c0105","c0106","c0107","c0109","c0110","c0114"]},{"id":"ngo-kiem-minh","name":"Ngô Kiếm Minh","cn":null,"aliases":["Ngô công tử","Ngô mỗ","Kẻ giả mạo họ Ngô"],"gioiTinh":"nam","theLuc":[{"ten":"Mặc phủ (thâm nhập giả mạo)","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân — võ công cao cường","trangThai":"song","blurb":"Thanh niên bạch diện khoảng hai mươi tuổi, mày kiếm mặt lạnh, vóc người thon dài, tự xưng là quan môn đệ tử học chân truyền võ công của Mặc đại phu. Thực chất là kẻ giả mạo, mang di thư và tín vật giả báo tin Mặc cư nhân đã chết rồi đính ước với Mặc Ngọc Châu nhằm đoạt Noãn dương bảo ngọc làm của hồi môn. Mặc phủ đã biết rõ hắn giả mạo và đang câu giờ điều tra.","vaiTro":"Kẻ xâm nhập Mặc phủ — mưu đoạt Noãn dương bảo ngọc","tinhCach":"Giả mạo, thủ đoạn — dựng di thư và tín vật giả để đoạt bảo vật; đa nghi, cảnh giác — tra hỏi gắt thân phận người lạ trong phủ","tabs":{"diem":[{"text":"Một năm trước mang di thư và tín vật (giả) tới Mặc phủ báo tang Mặc cư nhân, nhờ đó được công nhận là quan môn đệ tử","chuong":"@c105"},{"text":"Cùng Mặc Ngọc Châu cưỡi ngựa đi săn trở về, quan hệ tình cảm hai người thật sự sâu đậm","chuong":"@c107"},{"text":"Tra hỏi gắt thân phận Hàn Lập trong sân Mặc phủ nhưng bị qua mặt bằng lời khai là cháu Tam phu nhân","chuong":"@c114"}],"kinhLich":[{"chuong":105,"importance":"normal","tieuDe":"Báo tang Mặc cư nhân","text":"Một năm trước, mang di thư và tín vật tới Mặc phủ báo tin Mặc cư nhân đã chết. Nhờ đó được công nhận là quan môn đệ tử và đính ước với Mặc Ngọc Châu."},{"chuong":107,"importance":"normal","tieuDe":"Hàn Lập quan sát","text":"Cùng Mặc Ngọc Châu cưỡi ngựa đi săn trở về; nói nhỏ làm nàng ửng đỏ mặt — tình cảm hai người thật sự sâu. Hàn Lập nhìn từ xa đánh giá tướng mạo hắn hơn hẳn mình."},{"chuong":114,"importance":"normal","tieuDe":"Tra hỏi thân phận Hàn Lập — bị qua mặt","text":"Gặp Hàn Lập trong sân Mặc phủ, hỏi gắt thân phận. Hàn Lập đáp là cháu Tam phu nhân; Yến Ca (đại đồ đệ Mặc đại phu) có mặt không tra hỏi thêm — Ngô Kiếm Minh tạm thời thôi nghi ngờ."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc Ngọc Châu","tag":"tinh-cam","quanHe":"Hôn phu danh nghĩa — mục tiêu để đoạt bảo ngọc"},{"ten":"Hàn Lập","tag":"doi-dich","quanHe":"Đối thủ tiềm năng — đều nhắm vào Noãn dương bảo ngọc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":3,"nguon":["c0105","c0106","c0107","c0108","c0109","c0110","c0114"]},{"id":"tam-nuong","name":"Tam nương","cn":null,"aliases":["Tam muội","Tam phu nhân Lưu thị"],"gioiTinh":"nu","theLuc":[{"ten":"Mặc phủ","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Không rõ — nghi có khả năng mê hoặc bất thường","trangThai":"song","blurb":"Tam nương (bí danh Tam muội) là Tam phu nhân của Mặc đại phu và thân muội của môn chủ Trường Phong môn tại Khúc Lăng thành. Thiếu phụ chừng 23-24 tuổi cực kỳ kiều diễm, giọng kiều mỵ quyến rũ và ăn nói xấc xược, được Mặc đại phu nhận định là tính mạnh mẽ, hơi có dã tâm. Nàng thành thạo mị thuật mê hoặc và nhiều lần thi triển với Hàn Lập; khi bị y kháng lại, trong mắt lóe lên tia dị sắc gợi mở thân phận hoặc năng lực bất thường.","vaiTro":"Tam phu nhân Mặc phủ; nhân vật bí ẩn có mị thuật mê hoặc","tinhCach":"Mạnh mẽ, hơi có dã tâm; kiều mỵ phong tình, ăn nói xấc xược; bất cần, thích trêu ghẹo khêu gợi","tabs":{"diem":[{"text":"Thân muội môn chủ Trường Phong môn, được Mặc đại phu ghi trong di thư là tính mạnh mẽ, hơi dã tâm","chuong":"@c104"},{"text":"Dẫn đầu các phu nhân vào phòng với giọng kiều mỵ, khiến Hàn Lập thất thần đắm chìm","chuong":"@c110"},{"text":"Cùng các phu nhân giải mã ám thư bằng bột màu từ long văn giới chỉ, nắm kỹ thuật đặc biệt của nhóm","chuong":"@c112"},{"text":"Cười khêu gợi, liếc mắt trêu ghẹo Hàn Lập giữa lúc Nghiêm thị thương lượng nghiêm túc, lộ bản tính bất cần","chuong":"@c117"},{"text":"Dùng mị thuật mê hồn, miệng phả hương hoa lan dụ Hàn Lập chấp nhận điều kiện của Nghiêm thị","chuong":"@c118"}],"kinhLich":[{"chuong":104,"importance":"minor","text":"Nhắc đến trong di thư Mặc đại phu: tính mạnh mẽ, hơi dã tâm, thân muội môn chủ Trường Phong môn, chưa sinh con — cần chú ý."},{"chuong":110,"importance":"normal","tieuDe":"Xuất hiện và thi triển mê hoặc","text":"Dẫn đầu các phu nhân vào phòng với giọng kiều mỵ trách chồng bỏ đi. Hàn Lập vừa nhìn thất thần đắm chìm — được khí lạnh đan điền tự vận chuyển kéo tỉnh. Nàng thấy hắn tỉnh lại nhanh, trong mắt lóe tia dị sắc."},{"chuong":112,"importance":"minor","text":"Tham gia giải mã ám thư cùng các phu nhân bằng bột màu từ long văn giới chỉ; nắm kỹ thuật đặc biệt của nhóm phu nhân Mặc phủ."},{"chuong":116,"importance":"minor","text":"Khi Hàn Lập tạo hỏa cầu búng vào bàn bên cạnh, nàng cười ngã cười nghiêng không tin chuyện Hàn Lập là tu tiên giả; khi bàn hóa tro, mặt cắt không còn máu, vội lùi ra sau đống tro."},{"chuong":117,"importance":"minor","text":"Cười hì hì, liếc mắt khêu gợi Hàn Lập trong khi Nghiêm thị đang thương lượng nghiêm túc — lộ bản tính bất cần."},{"chuong":118,"importance":"normal","tieuDe":"Dùng mị thuật mê hồn dụ Hàn Lập","text":"Cười khêu gợi, miệng phả hương hoa lan dụ Hàn Lập chấp nhận điều kiện của Nghiêm thị. Hàn Lập vận Trường Xuân công, mắt phóng hàn ý lạnh khiến nụ cười nàng tắt hẳn — mị thuật vô hiệu. Không chịu rời quyền lực Kinh Giao hội đi ẩn cư."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"gia-dinh","quanHe":"Chồng (đã chết gần hai năm)"},{"ten":"Môn chủ Trường Phong môn","tag":"ho-hang","quanHe":"Huynh trưởng — ngoại thích đứng sau"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":3,"nguon":["c0104","c0110","c0112","c0116","c0117","c0118"]},{"id":"nhom-tu-tien-thang-tien-hoi","name":"Nhóm tu tiên Thăng Tiên hội (Lão Tam, Nhị ca)","cn":null,"aliases":["Người áo lam","Lão Tam","Người áo vàng","Nhị ca"],"gioiTinh":"nam","theLuc":[{"ten":"Thăng Tiên hội (chưa rõ môn phái)","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Tu tiên — Lão Tam: tầng 10 công pháp cơ sở (vừa luyện thành nhờ Trúc cơ đan); Nhị ca: cao hơn","trangThai":"song","blurb":"Hai tu sĩ gặp tại Hương Gia tửu lâu ở Gia Nguyên Thành. Lão Tam (áo lam, ~27-28 tuổi, mày rậm mắt to) vừa luyện thành mười tầng công pháp cơ sở nhờ Trúc cơ đan; pháp lực thâm hậu hơn Hàn Lập nhiều. Nhị ca (áo vàng, ~30 tuổi) tu vi cao hơn, chủ trương thanh tâm quả dục. Cả hai đến Lam Châu dự Thăng Tiên hội gặp 'đại ca'. Ánh mắt Lão Tam khiến Hàn Lập cảm thấy bị nhìn thấu — nhận ra và đánh giá Hàn Lập mới ở tầng 7-8.","vaiTro":"Tu tiên tới Lam Châu dự Thăng Tiên hội","tinhCach":[{"text":"Lão Tam: ham ăn, phóng khoáng — mấy năm không ăn thức ăn thế gian nên vào tửu lâu thưởng thức; bị Nhị ca trách làm thấp tâm tính tu tiên","chuong":106},{"text":"Nhị ca: nghiêm túc, chủ trương thanh tâm quả dục — trách Lão Tam ham vật chất","chuong":106}],"tabs":{"diem":[{"text":"Lão Tam nhận ra Hàn Lập là tu tiên cùng loại; đánh giá hắn 'tầng 7-8, miễn cưỡng đủ tư cách Thăng Tiên hội'","chuong":106},{"text":"Cả hai đang đi gặp 'đại ca' — người đứng đầu nhóm chưa lộ diện","chuong":106}],"kinhLich":[{"chuong":106,"importance":"normal","tieuDe":"Gặp tại Hương Gia tửu lâu","text":"Lão Tam ngồi cạnh Hàn Lập tại tửu lâu; ánh mắt khiến Hàn Lập hoảng sợ vì bị nhìn thấu. Hàn Lập dùng Thiên Nhãn Thuật phát hiện pháp lực Lão Tam vượt hơn mình nhiều. Ra khỏi tửu lâu, Lão Tam hội ngộ Nhị ca; hai người bàn về Thăng Tiên hội và Trúc cơ đan."}],"tuViMoc":[{"chuong":106,"canhGioi":"Lão Tam — tầng 10 công pháp cơ sở","text":"Vừa luyện thành mười tầng nhờ Trúc cơ đan; pháp lực thâm hậu hơn Hàn Lập nhiều.","importance":"normal"}],"nhanMach":[{"ten":"Đại ca (chưa rõ danh tính)","tag":"su-mon","quanHe":"Người đứng đầu nhóm — đang chờ gặp"},{"ten":"Hàn Lập","tag":"bat-ngo","quanHe":"Lão Tam nhận ra là tu tiên cùng loại tại tửu lâu"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0106"]},{"id":"yen-ca","name":"Yến Ca","cn":null,"aliases":["Đại đồ đệ Mặc đại phu"],"gioiTinh":"nam","theLuc":[{"ten":"Kinh Giao hội","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân — võ học","trangThai":"song","blurb":"Đại đồ đệ của Mặc đại phu; thương mày lợt, người cao lớn hào sảng. Thầm yêu Mặc Ngọc Châu từ nhỏ đến lớn — tỏ tình nhiều lần nhưng đều bị từ chối. Gặp Hàn Lập tại Mặc phủ; bị Hàn Lập dùng câu 'cháu Tam phu nhân' để qua mặt Ngô Kiếm Minh đang kiểm tra thân phận.","vaiTro":"Đại đồ đệ Mặc đại phu; thành viên cấp cao Kinh Giao hội","tinhCach":[{"text":"Hào sảng, cởi mở — chào Hàn Lập thân thiện dù không quen biết, không tra hỏi gắt","chuong":114}],"tabs":{"diem":[{"text":"Đại đồ đệ Mặc đại phu; võ học học từ Mặc đại phu","chuong":114},{"text":"Thầm yêu Mặc Ngọc Châu từ nhỏ, tỏ tình nhiều lần đều bị từ chối — tâm tình chưa nguôi","chuong":114}],"kinhLich":[{"chuong":114,"importance":"normal","tieuDe":"Gặp Hàn Lập tại Mặc phủ","text":"Xuất hiện trong khi Hàn Lập đang ở sân Mặc phủ cùng Ngô Kiếm Minh. Yến Ca chào Hàn Lập; Ngô Kiếm Minh hỏi gắt thân phận Hàn Lập — Hàn Lập đáp 'cháu Tam phu nhân'. Yến Ca không tra hỏi thêm, tình cờ giúp Hàn Lập qua mặt Ngô Kiếm Minh."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"su-mon","quanHe":"Sư phụ"},{"ten":"Mặc Ngọc Châu","tag":"tinh-cam","quanHe":"Người yêu đơn phương — tỏ tình nhiều lần bị từ chối"},{"ten":"Hàn Lập","tag":"bat-ngo","quanHe":"Đệ sư huynh (đệ đồ đệ của cùng một thầy)"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0104","c0114"]},{"id":"vuong-thi-ngu-phu-nhan","name":"Vương thị","cn":null,"aliases":["Ngũ phu nhân","Ngũ nương"],"gioiTinh":"nu","theLuc":[{"ten":"Mặc phủ (Ám Đà)","trangThai":"lanh-dao"}],"canhGioiCaoNhat":"Phàm nhân — nội công uyên thâm","trangThai":"song","blurb":"Vương thị (Ngũ nương) là Ngũ phu nhân của Mặc đại phu, nắm giữ Ám Đà — lực lượng bí mật thu bạc các trấn — theo di nguyện của phu quân. Là phàm nhân nhưng nội công uyên thâm, bà được Nghiêm thị tin cậy giao việc tuần tra vành đai và là người duy nhất trong nội bộ có năng lực phản đối, song chọn nhún nhường không nêu ý kiến.","vaiTro":"Ngũ phu nhân Mặc phủ; lãnh đạo Ám Đà — lực lượng bí mật Kinh Giao hội","tinhCach":"Lạnh lùng, mặt như núi tuyết; giỏi che giấu cảm xúc dù nội tâm dao động; nhún nhường trong nội bộ, không tranh quyền","tabs":{"diem":[{"text":"Được Nghiêm thị cử ra ngoài tuần tra vành đai khi Hàn Lập có mặt trong Mặc phủ, cho thấy nội công uyên thâm và được tin dùng","chuong":"@c111"},{"text":"Yêu cầu Hàn Lập thuật lại chi tiết cái chết của Mặc đại phu — mặt không đổi nhưng vặn vẹo ngón tay, để lộ tâm trạng dao động","chuong":"@c115"},{"text":"Là người duy nhất có thể phản đối Nghiêm thị nhưng tuyên bố để Tứ tỷ làm chủ, không nêu ý kiến","chuong":"@c118"}],"kinhLich":[{"chuong":111,"importance":"normal","tieuDe":"Tuần tra vành đai theo lệnh Nghiêm thị","text":"Nghiêm thị cử Vương thị ra ngoài tuần tra vành đai khi Hàn Lập có mặt trong Mặc phủ — xác nhận bà được giao nhiệm vụ nội công giám sát."},{"chuong":115,"importance":"normal","tieuDe":"Hỏi Hàn Lập về cái chết Mặc đại phu","text":"Yêu cầu Hàn Lập thuật lại chi tiết cái chết của Mặc đại phu. Mặt không đổi nhưng vặn vẹo ngón tay — bộc lộ tâm trạng bất thường."},{"chuong":118,"importance":"normal","tieuDe":"Không ý kiến khi Nghiêm thị cần thống nhất","text":"Nghiêm thị quay sang dò ý bà — người duy nhất có thể phản đối. Bà tuyên bố để Tứ tỷ làm chủ, không ý kiến — giúp Nghiêm thị yên tâm tiến hành đàm phán."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"gia-dinh","quanHe":"Chồng (đã chết)"},{"ten":"Nghiêm thị","tag":"gia-dinh","quanHe":"Tứ tỷ — người nắm quyền Kinh Giao hội; Vương thị dưới quyền về danh nghĩa nhưng kiểm soát Ám Đà độc lập"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":3,"nguon":["c0104","c0108","c0111","c0115","c0116","c0117","c0118"]},{"id":"ly-thi-nhi-phu-nhan","name":"Lý thị (Nhị phu nhân Mặc phủ)","cn":null,"aliases":["Nhị phu nhân","Nhị tỷ"],"gioiTinh":"nu","theLuc":[{"ten":"Mặc phủ","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Nhị phu nhân Lý thị của Mặc phủ, xuất thân con gái gia đình quyền quý. Bà là người đầu tiên nhận ra Hàn Lập là tu tiên giả khi hắn tạo hỏa cầu và là người lên tiếng cáo buộc hắn trong cuộc gặp mặc áo tang. Trong các phu nhân, bà là người duy nhất hơi động tâm trước đề nghị rời Lam Châu ẩn cư bình an.","vaiTro":"Nhị phu nhân Mặc phủ","tinhCach":"Hiểu lễ nghĩa, biết xấu hổ khi bị thuyết phục bằng ngụy biện; nhạy cảm, dễ lộ cảm xúc sợ hãi; hướng tới bình an","tabs":{"diem":[{"text":"Người lên tiếng cáo buộc Hàn Lập trong cuộc gặp mặc áo tang trắng","chuong":"@c115"},{"text":"Người đầu tiên nhận ra Hàn Lập là tu tiên giả khi hắn tạo hỏa cầu, buột miệng kêu 'Tu tiên giả!' với vẻ sợ hãi","chuong":"@c116"},{"text":"Bứt rứt cúi đầu xấu hổ khi Nghiêm thị dùng lý lẽ ngụy biện, cho thấy ý thức lễ nghĩa","chuong":"@c117"},{"text":"Phu nhân duy nhất hơi máy động tâm ý trước đề nghị rời Lam Châu ẩn cư bình an","chuong":"@c118"}],"kinhLich":[{"chuong":115,"importance":"normal","tieuDe":"Lên tiếng cáo buộc Hàn Lập","text":"Trong cuộc gặp mặt mặc áo tang trắng, Nhị phu nhân Lý thị là người lên tiếng cáo buộc Hàn Lập trước mặt các phu nhân."},{"chuong":116,"importance":"normal","tieuDe":"Nhận ra tu tiên giả — sợ hãi","text":"Khi Hàn Lập tạo hỏa cầu, buột miệng kêu 'Tu tiên giả!' với vẻ sợ hãi; bị Hàn Lập truy hỏi tại sao biết, được Nghiêm thị ngăn lại không cho trả lời."},{"chuong":117,"importance":"normal","tieuDe":"Bứt rứt, xấu hổ","text":"Khi Nghiêm thị dùng lý lẽ ngụy biện, Lý thị bứt rứt cúi đầu xấu hổ — phản ứng cho thấy ý thức lễ nghĩa và sự tự trọng."},{"chuong":118,"importance":"minor","text":"Phu nhân duy nhất hơi máy động tâm ý khi Hàn Lập đề nghị toàn Mặc phủ rời Lam Châu ẩn cư bình an."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"gia-dinh","quanHe":"Chồng (đã chết)"},{"ten":"Nghiêm thị","tag":"gia-dinh","quanHe":"Tứ tỷ — người nắm quyền thực tế Mặc phủ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0104","c0115","c0116","c0117","c0118"]},{"id":"tram-trong-son","name":"Trầm Trọng Sơn","cn":null,"aliases":["Viên tí","Bang chủ Tứ bình bang"],"gioiTinh":"nam","theLuc":[{"ten":"Tứ bình bang","trangThai":"da-roi"}],"canhGioiCaoNhat":"Phàm nhân — cao thủ võ lâm","trangThai":"tu-vong","blurb":"Trầm Trọng Sơn, ngoại hiệu 'Viên tí', là bang chủ Tứ bình bang cai quản khu Tây thành Gia Nguyên Thành, dưới trướng có tam đại hộ pháp Trầm Tam, Tiễn Tiến và Phạm Tự. Thói quen lui tới Tiêu Tương Viện gặp hoa khôi Kim Chi khiến hắn trở thành mục tiêu bị Hàn Lập nhắm tới. Hắn tử vong tại chương 122 vì bị Hàn Lập trộn Tiêu Hồn Tán vào rượu.","vaiTro":"Cựu bang chủ Tứ bình bang khu Tây thành Gia Nguyên Thành","tinhCach":"Sợ hãi trước thần tiên/tu tiên giả; ham mê tửu sắc, thường lui tới Tiêu Tương Viện; dễ bị thao túng","tabs":{"diem":[{"text":"Nắm quyền bang chủ Tứ bình bang khu Tây thành, chỉ huy tam đại hộ pháp","chuong":"@c121"},{"text":"Nghe thủ hạ báo tin về Thần tiên đại hội và sinh lòng sợ hãi thần tiên","chuong":"@c119"},{"text":"Bị Hàn Lập lập kế hoạch dùng Tôn nhị cẩu thay thế làm bang chủ bù nhìn","chuong":"@c120"},{"text":"Bị Hàn Lập cải trang tiểu nhị đột nhập Tiêu Tương Viện khi đang đàm hội","chuong":"@c121"},{"text":"Tử vong vì Tiêu Hồn Tán trộn trong rượu, chết cùng tam đại hộ pháp và các kỹ nữ","chuong":"@c122"}],"kinhLich":[{"chuong":119,"importance":"normal","tieuDe":"Biết tin Thần tiên đại hội — cấm truyền","text":"Thủ hạ báo lên hắn chuyện tình cờ nghe được đôi nam nữ tu tiên giả bàn về Thần tiên đại hội. Hắn sợ thần tiên trách tội, lập tức hạ lệnh cấm truyền — chỉ cấp cao Tứ bình bang biết."},{"chuong":120,"importance":"normal","tieuDe":"Bị Hàn Lập nhắm tới","text":"Hàn Lập lên kế hoạch dùng Tôn nhị cẩu thay thế hắn làm bang chủ bù nhìn, kiểm soát Tứ bình bang từ phía sau. Điểm yếu: thường xuyên tới Tiêu Tương Viện gặp Tiểu Kim Chi."},{"chuong":121,"importance":"normal","tieuDe":"Hàn Lập đột nhập Tiêu Tương Viện","text":"Đang đàm hội cùng tam đại hộ pháp tại phòng riêng Tiêu Tương Viện khi Hàn Lập cải trang thành tiểu nhị mang rượu vào."},{"chuong":122,"importance":"major","tieuDe":"Tử vong vì Tiêu Hồn Tán","text":"Uống rượu bị Hàn Lập trộn Tiêu Hồn Tán, chết cùng tam đại hộ pháp và các kỹ nữ."}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn nhị cẩu","tag":"noi-bo","quanHe":"Thủ hạ cũ — người thay thế làm bang chủ sau khi chết"},{"ten":"Tiểu Kim Chi","tag":"tinh-cam","quanHe":"Hoa khôi Tiêu Tương Viện — hay lui tới gặp"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0104","c0119","c0120","c0121","c0122"]},{"id":"tieu-kim-chi","name":"Tiểu Kim Chi","cn":null,"aliases":["Hoa khôi Tiêu Tương Viện"],"gioiTinh":"nu","theLuc":[{"ten":"Tiêu Tương Viện","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Hoa khôi của Tiêu Tương Viện (kỹ viện Tây thành Gia Nguyên Thành). Bang chủ Tứ bình bang Trầm Trọng Sơn thường xuyên lui tới gặp nàng — thói quen này được Hàn Lập dùng làm điểm xuất phát trong kế hoạch thâu tóm Tứ bình bang.","vaiTro":"Hoa khôi Tiêu Tương Viện; điểm liên hệ trong kế hoạch của Hàn Lập","tinhCach":[],"tabs":{"diem":[{"text":"Hoa khôi Tiêu Tương Viện; bang chủ Trầm Trọng Sơn thường xuyên đến gặp","chuong":120}],"kinhLich":[{"chuong":120,"importance":"minor","text":"Được nhắc tới là hoa khôi Tiêu Tương Viện mà bang chủ Trầm Trọng Sơn hay lui tới — Hàn Lập dùng thông tin này trong kế hoạch thâu tóm Tứ bình bang."}],"tuViMoc":[],"nhanMach":[{"ten":"Trầm Trọng Sơn","tag":"khach","quanHe":"Khách thường xuyên — bang chủ Tứ bình bang"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0120"]},{"id":"mac-phuong-vu","name":"Mặc Phượng Vũ","cn":null,"aliases":["Nhị tiểu thư Mặc phủ"],"gioiTinh":"nu","theLuc":[{"ten":"Mặc phủ","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Nhị tiểu thư của Mặc phủ, nghĩa nữ của Mặc đại phu. Khoảng 16-17 tuổi, mặc áo vàng. Giọng nói nhẹ nhàng; đặc biệt yêu thích y đạo, tìm đến Hàn Lập để xin lại di cảo y đạo của cha nuôi. Khác với đại tiểu thư Mặc Ngọc Châu (đã đính hôn Ngô Kiếm Minh).","vaiTro":"Nghĩa nữ của Mặc đại phu; học y đạo","tinhCach":[{"text":"Giọng nhẹ nhàng, khiêm tốn; chủ động hỏi thăm Hàn Lập về di cảo y đạo của cha","chuong":124}],"tabs":{"diem":[{"text":"Nghĩa nữ của Mặc đại phu; khoảng 16-17 tuổi, mặc áo vàng","chuong":122},{"text":"Đặc biệt yêu thích y đạo — nhận di cảo y đạo của Mặc đại phu từ Hàn Lập","chuong":124}],"kinhLich":[{"chuong":122,"importance":"minor","text":"Xuất hiện cùng Mặc Ngọc Châu và Mặc Thải Hoàn khi Hàn Lập đến Mặc phủ — được gọi là 'Mặc thị tam kiều'."},{"chuong":124,"importance":"normal","tieuDe":"Nhận di cảo y đạo từ Hàn Lập","text":"Đuổi theo Hàn Lập khi hắn rời Mặc phủ; giọng nhẹ nhàng hỏi về di cảo y đạo của Mặc đại phu. Hàn Lập trao lại di cảo cho nàng."},{"chuong":"@c0123","importance":"minor","text":"Khi Nghiêm thị đề nghị gả cả ba tỷ muội Mặc thị cho Hàn Lập, Mặc Phượng Vũ là người duy nhất trấn tĩnh: sắc mặt tái nhợt nhưng vẫn đưa tướng đứng vững, khác hẳn hai chị em kinh hoàng kêu lên — hé lộ tính cách điềm đạm hơn tuổi.","nguonNblm":true}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"gia-dinh","quanHe":"Cha nuôi (nghĩa phụ)"},{"ten":"Nghiêm thị","tag":"gia-dinh","quanHe":"Nghĩa mẫu — người thay Mặc đại phu nuốt thuốc con tin để bảo vệ con"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0122","c0123","c0124"]},{"id":"tich-thiet-nguu","name":"Tịch Thiết Ngưu","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tứ bình bang","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Phàm nhân — võ lâm","trangThai":"song","blurb":"Tráng hán khoảng 30 tuổi, mặt có nhiều thịt. Là nhân chứng nghe lén đôi tu tiên giả bàn về Thần tiên đại hội tại Lam Châu, cung cấp thông tin dẫn đường cho Hàn Lập tìm ra Thái Nam cốc. Được Hàn Lập phong làm phó bang chủ Tứ bình bang.","vaiTro":"Phó bang chủ Tứ bình bang; nhân chứng về Thái Nam cốc","tinhCach":[],"tabs":{"diem":[{"text":"Chờ Hàn Lập tại khách điếm cùng Tôn nhị cẩu sau khi Hàn Lập rời Mặc phủ","chuong":"@c124"},{"text":"Nhân chứng nghe lén đôi tu tiên giả bàn về đại hội thần tiên tại Lam Châu","chuong":"@c124"},{"text":"Khai báo chi tiết về 'Thái Nam cốc' — thông tin dẫn đường then chốt cho Hàn Lập","chuong":"@c125"},{"text":"Được Hàn Lập phong làm phó bang chủ Tứ bình bang","chuong":"@c125"}],"kinhLich":[{"chuong":124,"importance":"normal","tieuDe":"Chờ Hàn Lập tại khách điếm cùng Tôn nhị cẩu","text":"Đang chờ cùng Tôn nhị cẩu khi Hàn Lập về khách điếm sau khi rời Mặc phủ. Là nhân chứng nghe lén đôi tu tiên giả."},{"chuong":125,"importance":"major","tieuDe":"Khai báo về Thái Nam cốc — được phong phó bang chủ","text":"Thuật lại chi tiết: nữ tu tiên giả nhắc đến 'Thái Nam cốc' trước khi nói đến 'đại hội thần tiên'. Thông tin này giúp Hàn Lập suy ra địa điểm chính xác. Được Hàn Lập phong làm phó bang chủ Tứ bình bang."}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn nhị cẩu","tag":"noi-bo","quanHe":"Bang chủ Tứ bình bang — cấp trên"},{"ten":"Hàn Lập","tag":"chu","quanHe":"Người phong chức; chủ mưu từ xa"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0124","c0125"]},{"id":"van-tieu-son","name":"Vạn Tiểu Sơn","cn":null,"aliases":["Tiểu Sơn"],"gioiTinh":"nam","theLuc":[{"ten":"Vạn gia","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ (tu tiên giả chính thức)","trangThai":"song","blurb":"Thiếu niên tu tiên khoảng 15-16 tuổi, mặc bạch y, người của Vạn gia (Khô Nhai sơn) — gia tộc có tổ tiên là tán tu từng vào Cự Kiếm Môn. Tính hồn nhiên, hay trào phúng, tự hào về gia tộc. Chủ động kết giao và chỉ dẫn Hàn Lập khi cùng đường tới Thái Nam cốc. Nguồn thông tin tu tiên giới quý giá cho Hàn Lập trong c127-c128.","vaiTro":"Thành viên Vạn gia; người dẫn đường vào Thái Nam tiểu hội","tinhCach":[{"text":"Hồn nhiên, nhiệt tình — vui mừng gặp tán tu, không kỳ thị","chuong":128},{"text":"Thích khoe khoang, hứng chí kể hết kiến thức tu tiên khi được lắng nghe chăm chú","chuong":127}],"tabs":{"diem":[{"text":"Bạch y thiếu niên ~15-16 tuổi; người Vạn gia (Khô Nhai sơn)","chuong":126},{"text":"Tổ tiên Vạn gia là tán tu gia nhập Cự Kiếm Môn → tộc quy không kỳ thị tán tu","chuong":128}],"kinhLich":[{"chuong":126,"importance":"normal","tieuDe":"Gặp Hàn Lập tại Thái Nam sơn","text":"Hàn Lập nhận ra là tu tiên giả qua Thiên Nhãn Thuật. Đang tìm đường vào Thái Nam cốc cùng hướng Hàn Lập."},{"chuong":127,"importance":"normal","tieuDe":"Giảng giải hệ thống tu tiên cho Hàn Lập","text":"Trên đường tới cốc, hứng chí kể hết: hệ thống cảnh giới ba giai đoạn, thọ mệnh, bốn loại linh căn, bảy môn phái Việt quốc."},{"chuong":128,"importance":"normal","tieuDe":"Dùng Trương thông âm phù — dẫn Hàn Lập vào Thái Nam tiểu hội","text":"Xưng tên. Dùng Trương thông âm phù báo hiệu vào cốc; cùng Hàn Lập bước qua sương mù trận pháp vào Thái Nam tiểu hội."},{"chuong":"@c0129","importance":"normal","text":"Lần cuối xuất hiện (chia tay Hàn Lập): vào đến Thái Nam cốc, gọi 'Hàn đại ca' lại giới thiệu hắn với Thanh Nhan chân nhân (trưởng bối Thái Nam cốc, chỉ giao với gia phụ Vạn Tiểu Sơn, đồng chủ trì Thái Nam tiểu hội), xin Thanh Nhan chiếu cố Hàn Lập dù là tản tu. Bị Thanh Nhan trách tố gần lén nhà chạy đến đây và cảnh cáo nguy cơ gặp kẻ 'tâm thuật bất chánh' (ám chỉ Hàn Lập), rồi kéo đi gặp người nhà — hắn sợ nhất phải đối mặt Thất tỷ và Cửu ca. Buồn hiu như tù nhân bị áp giải, vẫn cố níu giữ Hàn Lập nhưng bị ngăn lại.","nguonNblm":true}],"tuViMoc":[],"nhanMach":[{"ten":"Hàn Lập","tag":"ban-be","quanHe":"Người bạn tán tu mới gặp — cùng đường vào Thái Nam cốc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0126","c0127","c0128"]},{"id":"thanh-nhan-chan-nhan","name":"Thanh Nhan chân nhân","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thái Nam cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Tu tiên giả — cấp độ chưa xác định","trangThai":"song","blurb":"Lão trưởng bối cai quản Thái Nam tiểu hội. Cao gầy, vai rộng, mặc nho sam xanh, mặt xanh lè. Bạn chí giao với phụ thân Vạn Tiểu Sơn. Nhận ra Hàn Lập là mộc-thuộc-tính tán tu Luyện Khí tầng thứ tám và nghi ngờ Hàn Lập có tâm thuật bất chánh.","vaiTro":"Lão trưởng bối quản lý Thái Nam cốc / tiểu hội","tinhCach":[{"text":"Nhãn lực tinh tường — nhận ra tu vi và thuộc tính linh căn của Hàn Lập chỉ qua một lần gặp","chuong":129},{"text":"Thận trọng, đa nghi: nghi ngờ Hàn Lập tâm thuật bất chánh dù Vạn Tiểu Sơn giới thiệu","chuong":129}],"tabs":{"diem":[{"text":"Cao gầy, vai rộng, mặc nho sam xanh, mặt xanh lè; bạn chí giao phụ thân Vạn Tiểu Sơn","chuong":129},{"text":"Nhận ra Hàn Lập: mộc-thuộc-tính tán tu, Luyện Khí tầng thứ tám","chuong":129}],"kinhLich":[{"chuong":129,"importance":"normal","tieuDe":"Gặp Hàn Lập — nghi ngờ tâm thuật","text":"Gặp Hàn Lập trong Thái Nam cốc; xác nhận qua nhãn lực hắn là mộc-thuộc-tính tán tu Luyện Khí tầng thứ tám. Tỏ vẻ nghi ngờ tâm thuật bất chánh. Hàn Lập khéo léo cáo từ."}],"tuViMoc":[],"nhanMach":[{"ten":"Vạn Tiểu Sơn","tag":"ban-be","quanHe":"Chí giao với phụ thân — biết rõ gia tộc Vạn gia"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0129"]},{"id":"tung-van-dao-si","name":"Tùng Văn đạo sĩ","cn":null,"aliases":["Quải Đan đạo sĩ"],"gioiTinh":"nam","theLuc":[{"ten":"Thanh Ngưu quan","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ tầng 7-8 (Trường Xuân công)","trangThai":"song","blurb":"Đạo sĩ khoảng 27-28 tuổi tu Trường Xuân công, tay cầm phất trần, xuất thân Thanh Ngưu quan trên Ngọa Ngưu sơn, ngoại hiệu 'Quải Đan đạo sĩ'. Dẫn đầu một nhóm tán tu tại Thái Nam tiểu hội, bề ngoài lôi kéo và đối đãi Hàn Lập niềm nở nhưng thực chất là kẻ chủ mưu tập sát hắn sau khi tiểu hội kết thúc.","vaiTro":"Trưởng nhóm tán tu tại Thái Nam tiểu hội; kẻ chủ mưu tập sát Hàn Lập","tinhCach":"Bề ngoài niềm nở, chính khí lẫm liệt; khéo hòa giải, thu phục nhân tâm; thâm hiểm, giả nghĩa để mưu hại","tabs":{"diem":[{"text":"Cùng nhóm tán tu tiếp cận mời Hàn Lập gia nhập, trao đạo phù chìa khóa tiểu lâu nhưng bị từ chối","chuong":"@c130"},{"text":"Chủ trì buổi giảng cho nhóm về Trúc cơ đan và Thăng tiên đại hội","chuong":"@c134"},{"text":"Giải thích bí ẩn về hai kỳ tài Luyện khí tầng mười một do gia tộc tu tiên tiềm phục bồi dưỡng","chuong":"@c135"},{"text":"Đứng ra hòa giải mâu thuẫn nội bộ nhóm và cảnh báo nguy cơ tán tu mất tích","chuong":"@c133"},{"text":"Chủ mưu tập sát: giả từ biệt, nhân lúc vỗ vai lén rắc phấn định vị lên áo Hàn Lập rồi bắn hỏa quang ra hiệu phục kích","chuong":"@c142"}],"kinhLich":[{"chuong":130,"importance":"normal","tieuDe":"Mời Hàn Lập vào nhóm — bị từ chối","text":"Cùng nhóm tán tu tiếp cận Hàn Lập tại Thái Nam tiểu hội. Trao đạo phù chìa khóa tiểu lâu. Hàn Lập từ chối vào nhóm, tự mình dạo chợ một mình."},{"chuong":132,"importance":"normal","tieuDe":"Đợi Hàn Lập — giới thiệu Ngô Cửu Chỉ và Hoàng Hiếu Thiên","text":"Chờ Hàn Lập ở lầu hai tiểu lâu. Niềm nở mời ngồi và giới thiệu hai người mới gia nhập nhóm: Ngô Cửu Chỉ (Vân Môn giản) và Hoàng Hiếu Thiên (Thạch Thác cốc)."},{"chuong":133,"importance":"normal","tieuDe":"Hòa giải nhóm, cảnh báo mất tích","text":"Đứng ra hòa giải mâu thuẫn giữa Ngô Cửu Chỉ (trộm đồ đùa) và Hồ Bình Cô; cảnh báo nguy cơ tán tu mất tích sau các kỳ Thái Nam hội, đề nghị cả nhóm cùng rời đi sau Thăng tiên đại hội."},{"chuong":134,"importance":"normal","tieuDe":"Chủ trì buổi giảng về Thăng tiên đại hội","text":"Xoa dịu Hồ Bình Cô để Hắc Mộc kể về Trúc cơ đan và Thăng tiên đại hội; giải thích thêm về công pháp kỳ lạ của Hoàng Hiếu Thiên; nhãn quang độc đáo (Hàn Lập cảm giác đạo sĩ đã nhìn ra thân phận tân thủ của mình)."},{"chuong":135,"importance":"normal","tieuDe":"Giải thích bí ẩn kỳ tài mười một tầng","text":"Giải thích lý do hai kỳ tài Luyện khí tầng mười một (người gia tộc tu tiên, tiềm phục đặc biệt bồi dưỡng) vẫn phải lên lôi đài Thăng tiên đại hội; chua chát thừa nhận tán tu thua kém gia tộc tu tiên về điều kiện; cuối chương trấn an và chuyển đề tài."},{"chuong":136,"importance":"normal","tieuDe":"Rủ Hàn Lập cùng đi — bị khéo léo từ chối","text":"Rủ Hàn Lập cùng nhóm rời đi sau đại hội; khuyên giải Ngô Cửu Chỉ khi thiếu niên bất mãn trước lời từ chối của Hàn Lập. Hàn Lập viện cớ chờ giao dịch xong mới quyết."},{"chuong":142,"importance":"normal","tieuDe":"Kẻ chủ mưu tập sát Hàn Lập","text":"Sau khi tiểu hội kết thúc, giả vờ từ biệt Hàn Lập, nhân lúc vỗ vai lén rắc phấn không màu không sắc lên áo hắn để định vị. Lùi lại sau khi nhóm ra khỏi cốc, lộ vẻ hung ác, bắn hỏa quang vào bụi cây ra hiệu cho đồng bọn phục kích. Âm mưu và bản chất nguy hiểm phơi bày sau lớp chính khí lẫm liệt bề ngoài."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0130","c0132","c0133","c0134","c0135","c0136","c0142"]},{"id":"ngo-cuu-chi","name":"Ngô Cửu Chỉ","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Vân Môn giản","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ — tầng 8 (đại viên mãn)","trangThai":"song","blurb":"Ngô Cửu Chỉ là thiếu niên tu tiên khoảng 16-17 tuổi thuộc Vân Môn giản, gia nhập nhóm tán tu Tùng Văn tại Thái Nam hội. Sở trường là thâu kỹ tinh xảo, thủ pháp ăn trộm mà hầu hết người tu tiên không phát giác. Tu vi đạt Luyện Khí kỳ tầng 8 đại viên mãn.","vaiTro":"Thành viên nhóm tán tu Tùng Văn tại Thái Nam hội","tinhCach":"Hào hứng, thích kết giao bằng hữu; ranh mãnh, tinh thông thâu kỹ; bất mãn khi bị cự tuyệt nhưng biết tự nhận thiếu sót","tabs":{"diem":[{"text":"Gia nhập nhóm tán tu Tùng Văn cùng Hoàng Hiếu Thiên, là người mới khiến cả nhóm chú ý","chuong":"@c132"},{"text":"Tiếp cận Hàn Lập với danh nghĩa kết nghĩa huynh đệ để thử thâu kỹ, nhưng bị Hàn Lập chộp cổ tay bắt quả tang","chuong":"@c133"},{"text":"Chủ động hỏi về Thăng tiên đại hội, hào hứng muốn lên lôi đài gia nhập đại môn phái","chuong":"@c134"},{"text":"Bực bội khi Hàn Lập từ chối đi cùng nhóm, viện lý do đoàn kết bảo vệ nhau, sau tự thấy hơi ép người nên bỏ qua","chuong":"@c136"},{"text":"Cùng nhóm sững sờ chứng kiến Hàn Lập đột phá Trường Xuân công tầng chín","chuong":"@c138"}],"kinhLich":[{"chuong":132,"importance":"normal","tieuDe":"Gia nhập nhóm Tùng Văn — khiến đạo sĩ đau đầu","text":"Cùng Hoàng Hiếu Thiên xuất hiện trong phòng họp nhóm Tùng Văn tại tiểu lâu, là hai người mới khiến cả Tùng Văn đạo sĩ đau đầu."},{"chuong":133,"importance":"normal","tieuDe":"Bị Hàn Lập bắt quả tang dùng thâu kỹ","text":"Tiếp cận Hàn Lập bằng cách muốn kết nghĩa huynh đệ, thực chất để thử thâu kỹ; bị Hàn Lập chộp cổ tay bắt quả tang. Sau khi Tùng Văn hòa giải, thành khẩn giải thích không có ác ý và cam kết không dùng thâu kỹ với đồng đạo trong đại hội nữa."},{"chuong":134,"importance":"normal","tieuDe":"Hỏi về Thăng tiên đại hội","text":"Chủ động hỏi về Thăng tiên đại hội, thúc đẩy buổi giảng giải; hào hứng muốn lên lôi đài gia nhập đại môn phái sau khi nghe Hắc Mộc kể."},{"chuong":136,"importance":"normal","tieuDe":"Bất mãn khi Hàn Lập không chịu đi cùng","text":"Bực bội khi Hàn Lập từ chối đi cùng nhóm, nêu lý do đoàn kết bảo vệ nhau; tự thấy hơi ép người nên bỏ qua sau khi Tùng Văn khuyên giải."},{"chuong":138,"importance":"minor","tieuDe":"Chứng kiến Hàn Lập đột phá tầng chín","text":"Cùng nhóm trợn mắt há hốc mồm khi Hàn Lập đột phá Trường Xuân công tầng chín."}],"tuViMoc":[],"nhanMach":[{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu Thái Nam hội"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0132","c0133","c0134","c0136","c0138"]},{"id":"hoang-hieu-thien","name":"Hoàng Hiếu Thiên","cn":null,"aliases":["Hoàng huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thác cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ (pháp lực mạnh nhất nhóm tán tu — dường như hơn Tùng Văn đạo sĩ)","trangThai":"song","blurb":"Người mập mạp da trắng nõn khoảng 21-22 tuổi, tu tiên Thạch Thác cốc. Pháp lực cường đại nhất trong nhóm tán tu Tùng Văn, thậm chí mạnh hơn cả Tùng Văn đạo sĩ. Tính lạnh lùng, không khách khí, không ai dám chọc vì sợ thực lực. Công pháp tu luyện đặc biệt — cần ngủ.","vaiTro":"Thành viên nhóm tán tu Tùng Văn tại Thái Nam hội","tinhCach":[{"text":"Lạnh lùng, không khách khí — thẳng thắn nói đã biết chuyện Thăng tiên hội rồi, về ngủ, không đợi ai","chuong":134},{"text":"Thái độ âm trầm khi nghe cảnh báo tán tu mất tích","chuong":133}],"tabs":{"diem":[{"text":"21-22 tuổi, mập mạp da trắng nõn; Thạch Thác cốc","chuong":132},{"text":"Pháp lực cường đại nhất nhóm — mạnh hơn cả Tùng Văn đạo sĩ; không ai dám để ý vì sợ thực lực","chuong":133},{"text":"Công pháp tu luyện kỳ lạ cần ngủ — Tùng Văn giải thích hộ, không phải cố ý thất lễ","chuong":134}],"kinhLich":[{"chuong":132,"importance":"normal","tieuDe":"Gia nhập nhóm Tùng Văn","text":"Cùng Ngô Cửu Chỉ gia nhập nhóm tán tu Tùng Văn tại tiểu lâu; sự xuất hiện của hai người khiến Tùng Văn đạo sĩ đau đầu."},{"chuong":133,"importance":"normal","tieuDe":"Chứng kiến sự cố thâu kỹ","text":"Có mặt trong phòng họp; ánh mắt âm trầm khi nghe Tùng Văn cảnh báo về tán tu mất tích sau Thái Nam hội."},{"chuong":134,"importance":"normal","tieuDe":"Bỏ về ngủ giữa chừng","text":"Lạnh lùng tuyên bố đã rõ chuyện Thăng tiên đại hội, rời phòng về ngủ mà không đợi ai. Tùng Văn giải thích hộ: công pháp hắn kỳ lạ cần ngủ."}],"tuViMoc":[],"nhanMach":[{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu, thường giải thích hộ tính cách lạnh lùng của Hoàng Hiếu Thiên"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0132","c0133","c0134"]},{"id":"hac-moc","name":"Hắc Mộc","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Lang lĩnh","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ","trangThai":"song","blurb":"Một trong hai huynh đệ song sinh Hắc Mộc–Hắc Kim từ Thương Lang lĩnh, hiện là thành viên nhóm tán tu do Tùng Văn dẫn dắt tại Thái Nam hội. Am hiểu tu tiên giới, anh là người giảng giải chi tiết cho cả nhóm về Trúc cơ đan cùng cơ chế Thăng tiên đại hội. Xuất hiện lần đầu khi cùng Hắc Kim đón dẫn Hàn Lập vào phòng họp nhóm.","vaiTro":"Thành viên nhóm tán tu Tùng Văn tại Thái Nam hội","tinhCach":"Am hiểu tu tiên giới, giỏi giảng giải; điềm tĩnh nhưng biến sắc trước hiểm nguy; đôi lúc uể oải, bi quan về triển vọng tán tu","tabs":{"diem":[{"text":"Cùng Hắc Kim đón và dẫn Hàn Lập vào phòng họp nhóm tại tiểu lâu","chuong":"@c132"},{"text":"Biến sắc và đồng ý cùng nhóm rời đi khi Tùng Văn cảnh báo tán tu bị mất tích","chuong":"@c133"},{"text":"Giảng giải cho cả nhóm về nguồn gốc Trúc cơ đan, cơ chế Thăng tiên đại hội và lý do tán tu khó đoạt lôi đài","chuong":"@c134"},{"text":"Nhận định Thăng tiên đại hội ngày càng kịch liệt và nêu tỷ lệ trúc cơ thất bại cao của tán tu","chuong":"@c135"}],"kinhLich":[{"chuong":132,"importance":"normal","tieuDe":"Đón Hàn Lập — dẫn vào phòng","text":"Cùng Hắc Kim đứng ở đầu cầu thang lầu hai tiểu lâu, đón và dẫn Hàn Lập dọc hành lang vào phòng họp nhóm."},{"chuong":133,"importance":"normal","tieuDe":"Chứng kiến sự cố thâu kỹ, biến sắc nghe tin mất tích","text":"Có mặt trong phòng; biến sắc và đồng ý cùng nhau rời đi sau hội khi nghe Tùng Văn cảnh báo tán tu bị mất tích một cách khó hiểu."},{"chuong":134,"importance":"normal","tieuDe":"Giảng giải về Thăng tiên đại hội","text":"Người giảng giải cho cả nhóm về nguồn gốc Trúc cơ đan, cơ chế Thăng tiên đại hội, lý do tán tu khó đoạt lôi đài."},{"chuong":135,"importance":"normal","tieuDe":"Tiếp tục bàn luận về lôi đài","text":"Lẩm bẩm Thăng tiên đại hội ngày càng kịch liệt; uể oải nêu tỷ lệ trúc cơ thất bại của tán tu."}],"tuViMoc":[],"nhanMach":[{"ten":"Hắc Kim","tag":"gia-dinh","quanHe":"Huynh đệ song sinh"},{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu Thái Nam hội"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0130","c0132","c0133","c0134","c0135"]},{"id":"hac-kim","name":"Hắc Kim","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Lang lĩnh","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ","trangThai":"song","blurb":"Một trong hai huynh đệ song sinh Hắc Mộc–Hắc Kim từ Thương Lang lĩnh. Ít nói hơn huynh; quan sát sắc bén — đột nhiên phát biểu rằng người pháp lực yếu hơn vẫn có thể thắng nếu có pháp phù/pháp khí lợi hại.","vaiTro":"Thành viên nhóm tán tu Tùng Văn tại Thái Nam hội","tinhCach":[{"text":"Ít nói nhưng nhận xét sắc bén — từ đầu im lặng rồi bất ngờ phát biểu chính xác về chiến thuật pháp phù trong lôi đài","chuong":135}],"tabs":{"diem":[{"text":"Huynh đệ song sinh với Hắc Mộc; xuất thân Thương Lang lĩnh","chuong":130},{"text":"Từ đầu vào phòng im lặng; bất ngờ lên tiếng: pháp lực cao chưa chắc thắng nếu địch có pháp phù/pháp khí lợi hại","chuong":135}],"kinhLich":[{"chuong":132,"importance":"normal","tieuDe":"Đón Hàn Lập — dẫn vào phòng","text":"Cùng Hắc Mộc đứng ở đầu cầu thang lầu hai tiểu lâu, đón và dẫn Hàn Lập dọc hành lang vào phòng họp nhóm."},{"chuong":135,"importance":"normal","tieuDe":"Phát biểu về chiến thuật lôi đài","text":"Người duy nhất im lặng từ đầu phòng, đột nhiên lên tiếng: người pháp lực yếu hơn nhưng có pháp phù uy lực lớn hoặc pháp khí cực lợi hại vẫn có thể hạ kẻ mạnh hơn — nhận định được Tùng Văn đồng tình."}],"tuViMoc":[],"nhanMach":[{"ten":"Hắc Mộc","tag":"gia-dinh","quanHe":"Huynh đệ song sinh"},{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu Thái Nam hội"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0130","c0132","c0135"]},{"id":"hong-lien-tan-nhan","name":"Hồng Liên tán nhân","cn":null,"aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Phi Liên động","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ","trangThai":"song","blurb":"Nữ tán tu từ Phi Liên động. Vốn trầm mặc ít nói trong nhóm Tùng Văn, nhưng đôi khi nêu nghi vấn sắc sảo. Dứt khoát đồng ý tiếp tục đi cùng nhóm sau Thái Nam hội.","vaiTro":"Thành viên nhóm tán tu Tùng Văn tại Thái Nam hội","tinhCach":[{"text":"Trầm mặc ít nói, nhưng lên tiếng hỏi đúng điểm mấu chốt khi không phục","chuong":135},{"text":"Dứt khoát — đồng ý đi cùng nhóm không chần chừ","chuong":136}],"tabs":{"diem":[{"text":"Nữ tán tu, Phi Liên động; ít nói nhất trong nhóm Tùng Văn","chuong":130}],"kinhLich":[{"chuong":133,"importance":"normal","tieuDe":"Vẻ mặt mờ mịt nghe tin tán tu mất tích","text":"Khi Tùng Văn cảnh báo về tán tu mất tích sau Thái Nam hội, Hồng Liên tán nhân lộ vẻ mặt mờ mịt."},{"chuong":135,"importance":"normal","tieuDe":"Hỏi về kỳ tài mười một tầng","text":"Đặt câu hỏi sắc sảo: chẳng lẽ kỳ tài công pháp mười một tầng phải lên đài tỷ thí, các tu tiên phái không chủ động thu nhận sao. Sau đó không phục, tức giận hỏi tán tu có thật không bằng đệ tử gia tộc tu tiên."},{"chuong":136,"importance":"normal","tieuDe":"Dứt khoát theo nhóm","text":"Dứt khoát đồng ý tiếp tục đi cùng nhóm sau Thái Nam hội khi Tùng Văn rủ."}],"tuViMoc":[],"nhanMach":[{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu Thái Nam hội"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":6,"nguon":["c0130","c0133","c0135","c0136"]},{"id":"kho-tang-dai-su","name":"Khổ Tang đại sư","cn":null,"aliases":["tiểu hòa thượng"],"gioiTinh":"nam","theLuc":[{"ten":"Bồ Lộ sơn","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ","trangThai":"song","blurb":"Hòa thượng từ Bồ Lộ sơn, thành viên nhóm tán tu Tùng Văn, cảnh giới Luyện Khí kỳ. Khi Hàn Lập tìm đến, thường ngồi tụng Kim cương kinh với dáng vẻ cao tăng. Là người truyền dạy cho Hàn Lập về đạo chế linh phù cùng phù thuật một cách cặn kẽ và có căn cứ thực tiễn.","vaiTro":"Thành viên nhóm tán tu Tùng Văn; chỉ điểm Hàn Lập về chế phù","tinhCach":"Điềm tĩnh, thường tụng kinh với dáng vẻ cao tăng đắc đạo; tận tình chỉ điểm, giảng giải tường tận và thực tiễn","tabs":{"diem":[{"text":"Gặp Hàn Lập tại tiểu lâu, truyền lời Tùng Văn đang đợi","chuong":"@c132"},{"text":"Chỉ điểm Hàn Lập nguyên liệu chế linh phù: đan sa từ máu linh khí yêu thú và bút lông yêu thú","chuong":"@c136"},{"text":"Giải thích đạo chế phù, trấn an người mới thất bại hơn trăm lần là bình thường sau khi Hàn Lập hỏng 12 lần Định thần phù","chuong":"@c138"}],"kinhLich":[{"chuong":132,"importance":"normal","tieuDe":"Gặp Hàn Lập, truyền lời Tùng Văn","text":"Ngồi tụng Kim cương kinh ở lầu một tiểu lâu khi Hàn Lập tới. Mãi mới mở mắt và truyền lời Tùng Văn đang đợi ở lầu hai."},{"chuong":136,"importance":"normal","tieuDe":"Chỉ điểm Hàn Lập về chế linh phù","text":"Giảng cho Hàn Lập nguyên liệu chế linh phù: cần đan sa từ máu linh khí yêu thú, và bút (lông yêu thú hoặc bút than với thiên tài địa bảo); bút thường tỉ lệ thành công thấp đến đáng thương."},{"chuong":138,"importance":"normal","tieuDe":"Chỉ điểm về đạo chế phù và phù thuật","text":"Sau khi Hàn Lập thất bại 12 lần chế Định thần phù, giải thích: người mới thất bại hơn trăm lần là bình thường; chỉ sau vạn lần luyện tập mới thành phù sư hợp cách; đồng thời giải thích sự khác biệt giữa chế phù và phù thuật. Hàn Lập từ đó tạm từ bỏ tự chế phù."}],"tuViMoc":[],"nhanMach":[{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu Thái Nam hội"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0130","c0132","c0133","c0136","c0138"]},{"id":"ho-binh-co","name":"Hồ Bình Cô","cn":null,"aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Thiên thủy trại","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ","trangThai":"song","blurb":"Nữ tán tu từ Thiên thủy trại, vợ của Hùng Đại Lực. Người am hiểu thực tế lôi đài Thăng tiên hội — từng chính mắt chứng kiến, sắc mặt trắng bệch khi nhớ lại. Nhanh nhảu, hay cãi, nhưng biết điểm dừng và thực tế.","vaiTro":"Thành viên nhóm tán tu Tùng Văn; người giảng giải về Thăng tiên hội","tinhCach":[{"text":"Nhanh nhảu, hay cãi nhau với Ngô Cửu Chỉ; xô ghế đứng dậy sắc mặt xanh mét khi bị khiêu khích","chuong":133},{"text":"Thực tế, từng trải — từng chứng kiến lôi đài Thăng tiên hội lần trước, kiêng kỵ sự tàn khốc của nó","chuong":134},{"text":"Cứng đầu nhưng không cố chấp — miễn cưỡng chấp nhận hòa giải với Ngô Cửu Chỉ","chuong":133}],"tabs":{"diem":[{"text":"Vợ Hùng Đại Lực (câm); Thiên thủy trại; hai vợ chồng dự tính ở lại Luyện khí kỳ cả đời, không lên lôi đài","chuong":134},{"text":"Từng chính mắt xem Thăng tiên hội lần trước; nhớ lại vẫn sợ; biết rõ số lượng chết/bị thương","chuong":134}],"kinhLich":[{"chuong":133,"importance":"normal","tieuDe":"Xô ghế cãi nhau với Ngô Cửu Chỉ","text":"Từng bị Ngô Cửu Chỉ trộm đồ; tức giận châm chọc, xô ghế đứng dậy. Sau khi Tùng Văn hòa giải, miễn cưỡng chấp nhận; hâm mộ vận may của Hàn Lập vì đã bán hết hàng từ sớm."},{"chuong":134,"importance":"normal","tieuDe":"Bất mãn, muốn bàn về tán tu mất tích","text":"Ban đầu bất mãn khi chuyển sang bàn về Thăng tiên hội; sau ổn định, đồng ý kể về sự tàn khốc của lôi đài. Sắc mặt trắng bệch khi nhớ lại cảnh chứng kiến."},{"chuong":135,"importance":"normal","tieuDe":"Giảng giải chi tiết lôi đài Thăng tiên hội","text":"Người giảng giải chính về điều kiện báo danh (tầng bảy+, dưới bốn mươi tuổi), bảy lôi đài thất đại tiên phái, thể thức tỷ thí loại trực tiếp; kể số người chết lần trước (hơn trăm) — sắc mặt lạnh tự giễu về bất lợi của tán tu."}],"tuViMoc":[],"nhanMach":[{"ten":"Hùng Đại Lực","tag":"gia-dinh","quanHe":"Chồng — câm bẩm sinh, mọi việc Hồ Bình Cô làm chủ"},{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu Thái Nam hội"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0130","c0133","c0134","c0135"]},{"id":"hung-dai-luc","name":"Hùng Đại Lực","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên thủy trại","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ","trangThai":"song","blurb":"Tán tu Thiên thủy trại, chồng của Hồ Bình Cô. Câm bẩm sinh nên mọi việc do phu nhân làm chủ. Vóc người to lớn, mang đại đao sau lưng.","vaiTro":"Thành viên nhóm tán tu Tùng Văn tại Thái Nam hội","tinhCach":[{"text":"Bảo vệ phu nhân — đưa tay ra đại đao sau lưng khi Ngô Cửu Chỉ và Hồ Bình Cô xung đột","chuong":133},{"text":"Ân cần — vòng tay qua vai an ủi Hồ Bình Cô khi nàng sợ hãi nhớ lại cảnh lôi đài","chuong":134}],"tabs":{"diem":[{"text":"Chồng Hồ Bình Cô; câm bẩm sinh; to lớn, mang đại đao; Thiên thủy trại","chuong":133}],"kinhLich":[{"chuong":133,"importance":"normal","tieuDe":"Định rút đao bảo vệ phu nhân","text":"Khi Hồ Bình Cô và Ngô Cửu Chỉ tranh chấp kịch liệt, trợn mắt đưa tay vào đại đao sau lưng. Sau khi Tùng Văn hòa giải, thôi."},{"chuong":134,"importance":"normal","tieuDe":"An ủi phu nhân","text":"Vòng tay qua vai Hồ Bình Cô an ủi khi nàng sắc mặt trắng bệch nhớ lại cảnh lôi đài Thăng tiên hội."}],"tuViMoc":[],"nhanMach":[{"ten":"Hồ Bình Cô","tag":"gia-dinh","quanHe":"Vợ — làm chủ mọi việc trong cặp vì Hùng Đại Lực câm"},{"ten":"Tùng Văn đạo sĩ","tag":"dong-doi","quanHe":"Trưởng nhóm tán tu Thái Nam hội"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":6,"nguon":["c0130","c0133","c0134"]},{"id":"diep-bao","name":"Diệp Báo","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Diệp gia — Tần Diệp lĩnh","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ","trangThai":"song","blurb":"Tự xưng người của Tần Diệp lĩnh (Diệp gia). Đi chân không, mặt như ngựa. Trả giá Phi thiên phù bị từ chối, tức giận đe dọa chủ quầy sẽ tính sổ sau đại hội. Sự xuất hiện của hắn khiến Hàn Lập cảnh giác vì Chu Nho (người Diệp gia bị Hàn Lập giết) từng nhắc tới Tần Diệp lĩnh.","vaiTro":"Thành viên Diệp gia; xuất hiện tại Thái Nam hội","tinhCach":[{"text":"Nóng nảy, dễ tức — thất bại trong mặc cả thì lập tức đe dọa đối phương","chuong":131},{"text":"Mượn danh thế lực — dựa vào thân phận Diệp gia để không sợ hậu quả khi đe dọa","chuong":131}],"tabs":{"diem":[{"text":"Đi chân không, mặt như ngựa; tự xưng người Tần Diệp lĩnh Diệp gia","chuong":131},{"text":"Đệ tử Diệp gia xuất hiện tại Thái Nam hội, trả giá Phi thiên phù bị chủ quầy từ chối","chuong":131}],"kinhLich":[{"chuong":131,"importance":"normal","tieuDe":"Trả giá Phi thiên phù — đe dọa chủ quầy","text":"Trả giá hai mươi khối linh thạch mua Phi thiên phù bị chủ quầy từ chối. Tức giận, tự xưng Diệp Báo của Tần Diệp lĩnh, đe dọa sau đại hội sẽ tính sổ, rồi bỏ đi. Sự xuất hiện khiến Hàn Lập cảnh giác vì biết hắn là người Diệp gia."},{"chuong":139,"importance":"normal","tieuDe":"Đệ tử Diệp gia có mặt tại quầy rao bán Tàn Phiến","text":"Một đệ tử Diệp gia (áo gắn đồ án lá cây) đang giữ bát vàng Hồi phong bát tại quầy nơi hán tử da đen rao bán Tàn Phiến; từ chối đổi và đòi giá cao. Không nêu đích danh Diệp Báo nhưng là người Diệp gia cùng bối cảnh."}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Nho","tag":"dong-toc","quanHe":"Cùng là người Diệp gia Tần Diệp lĩnh — Chu Nho đã bị Hàn Lập giết, Diệp Báo có thể là nguy cơ tiếp theo"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0131","c0139"]},{"id":"chung-linh-dao","name":"Chung Linh Đạo","cn":null,"aliases":["Chung Chưởng môn","Chung đại Chưởng môn"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Trúc Cơ kỳ hậu kỳ","trangThai":"song","blurb":"Chưởng môn hiện tại của Hoàng Phong Cốc, hơn trăm tuổi nhưng dáng vẻ như người trung niên, tu vi đạt hậu kỳ Trúc Cơ kỳ. Ông chủ trì việc phân chia Trúc Cơ đan trong môn phái và thu nhận Hàn Lập làm đệ tử theo lời hứa gắn với Thăng Tiên Lệnh. Về sau ông tiếp Hàn Lập tại Nghị sự điện, kinh ngạc trước việc ngụy linh căn bốn thuộc tính của y vẫn tiến bộ.","vaiTro":"Chưởng môn Hoàng Phong Cốc, tu vi hậu kỳ Trúc Cơ kỳ","tinhCach":"Trầm ổn, công chính nghiêm minh; uy vọng cao, giữ chữ tín; xử sự lưỡng toàn, khéo dàn xếp","tabs":{"diem":[{"text":"Đạt tu vi hậu kỳ Trúc Cơ kỳ, hơn trăm tuổi mà dáng vẻ như trung niên","chuong":"@c0144"},{"text":"Chủ trì cuộc họp quản sự, phán quyết ưu tiên người cầm Thăng Tiên Lệnh khi phân chia Trúc Cơ đan","chuong":"@c0144"},{"text":"Chính thức thu nhận Hàn Lập làm đệ tử và dàn xếp lưỡng toàn vụ Trúc Cơ đan","chuong":"@c0147"},{"text":"Phát biểu cổ vũ đoàn đệ tử áo vàng trước chuyến Huyết Cấm Thí Luyện","chuong":"@c0174"},{"text":"Tiếp và chúc mừng Hàn Lập tại Nghị sự điện, kinh ngạc trước tiến bộ của ngụy linh căn bốn thuộc tính","chuong":"@c0219"}],"kinhLich":[{"chuong":144,"importance":"normal","tieuDe":"Chủ trì phân chia Trúc Cơ đan","text":"Chủ trì cuộc họp hơn mười quản sự, ra phán quyết về phân chia Trúc Cơ đan: ưu tiên người cầm Thăng Tiên Lệnh, tiểu cô nương hậu nhân Hồng Phất sư thúc, và người mang dị linh căn; cho phép Diệp lão giả tiếp cận giao dịch nhưng cấm cưỡng ép."},{"chuong":147,"importance":"normal","tieuDe":"Thu nhận Hàn Lập — dàn xếp vụ Trúc Cơ đan","text":"Chính thức thu Hàn Lập làm đệ tử Hoàng Phong Cốc. Dàn xếp lưỡng toàn: Hàn Lập nhường đan, Diệp Tính bồi thường tổn thất. Phân phó Vương sư đệ an bài chỗ ở và phổ biến môn quy."},{"chuong":174,"importance":"normal","tieuDe":"Phát biểu cổ vũ trước chuyến Huyết Cấm Thí Luyện","text":"Phát biểu cổ vũ đoàn đệ tử áo vàng tại nghị sự đại điện trước khi họ xuất phát vào cấm địa. Nghênh đón và giới thiệu Lý Sư Tổ (gọi 'Lý sư thúc') trước mặt toàn thể đệ tử."}],"tuViMoc":[{"chuong":144,"canhGioi":"Trúc Cơ kỳ hậu kỳ","text":"Hơn trăm tuổi, tu vi hậu kỳ Trúc Cơ kỳ; dáng như trung niên ba mươi.","importance":"normal"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0144","c0145","c0147","c0148","c0174"]},{"id":"diep-tinh-lao-gia","name":"Diệp Tính lão giả","cn":null,"aliases":["Diệp lão giả","Diệp sư thúc","Diệp sư huynh","Diệp Đường chủ"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"},{"ten":"Diệp gia","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Trúc Cơ kỳ (quản sự)","trangThai":"song","blurb":"Diệp Tính lão giả là quản sự Trúc Cơ kỳ của Hoàng Phong Cốc kiêm Đường chủ Bách Ky đường, xuất thân Diệp gia. Vì cháu mình bị tước suất Trúc Cơ đan, ông tìm cách mặc cả với Hàn Lập để đổi lấy đan dược, rồi lại hối ước hoãn giao vật phẩm bồi thường và bị Ngô Tính nắm thóp. Về sau ông biết Hàn Lập là ký danh đệ tử của Lý sư tổ.","vaiTro":"Quản sự Hoàng Phong Cốc; Đường chủ Bách Ky đường, thuộc Diệp gia","tinhCach":"Nóng nảy, dễ tức giận trong nghị sự; thiên vị người thân, tìm cách mưu lợi cho cháu; giỏi mặc cả nhưng hay bội tín, hối ước","tabs":{"diem":[{"text":"Tức giận trong cuộc họp vì cháu mình bị tước suất Trúc Cơ đan, nhường cho người cầm Thăng Tiên Lệnh","chuong":"@c0144"},{"text":"Gặp riêng Hàn Lập ở Nghênh Tân lâu, niềm nở đề nghị mua Trúc Cơ đan với giá bảy tám khối linh thạch bậc trung","chuong":"@c0145"},{"text":"Thuyết phục Hàn Lập rằng tư chất tứ linh căn dùng đan tỉ lệ thành công thấp, nên đổi lấy vật hữu dụng","chuong":"@c0146"},{"text":"Hào phóng cho Hàn Lập tùy ý chọn công tác trồng trọt dù chưa hết một tháng làm quen","chuong":"@c0149"},{"text":"Hối ước, hoãn giao một phần vật phẩm bồi thường với cớ luyện Hợp Khí đan cho cháu, bị Ngô Tính nắm thóp","chuong":"@c0150"},{"text":"Biết Hàn Lập là ký danh đệ tử của Lý sư tổ sau khi từng ăn bớt phân nửa đồ của Hàn Lập","chuong":"@c0213"}],"kinhLich":[{"chuong":144,"importance":"normal","tieuDe":"Cãi vã về Trúc Cơ đan","text":"Tức giận trong cuộc họp vì cháu mình bị tước suất Trúc Cơ đan nhường cho người cầm Thăng Tiên Lệnh. Cùng Ngô lão giả lập mưu: dụ người tư chất kém tự nguyện nhường đan."},{"chuong":145,"importance":"normal","tieuDe":"Gặp riêng Hàn Lập — đề nghị mua Trúc Cơ đan","text":"Vào Nghênh Tân lâu gặp Hàn Lập, thái độ niềm nở gọi 'Diệp sư thúc', chào giá bảy tám khối linh thạch bậc trung và vật phẩm đổi lấy Trúc Cơ đan."},{"chuong":146,"importance":"normal","tieuDe":"Chốt giao dịch","text":"Thuyết phục Hàn Lập: tư chất tứ linh căn dùng đan tỉ lệ thành công thấp, chi bằng đổi lấy vật hữu dụng. Đề nghị cho Hàn Lập tùy chọn công tác tạp vụ — chiêu sát thủ cuối cùng. Giao dịch thành: Hàn Lập nhường đan, được chọn công tác trồng linh dược."},{"chuong":149,"importance":"normal","tieuDe":"Hào phóng duyệt công tác cho Hàn Lập","text":"Xuất hiện ở Bách Ky đường, hào phóng cho Hàn Lập tùy ý chọn công tác trồng trọt dù chưa hết một tháng làm quen."},{"chuong":150,"importance":"normal","tieuDe":"Hối ước — bị Ngô Tính nắm thóp","text":"Hoãn giao một phần vật phẩm bồi thường với cớ luyện Hợp Khí đan cho cháu sắp Trúc Cơ. Hàn Lập nhẫn nhịn. Sau khi Hàn Lập đi, bị Ngô Tính lộ rõ đang khống chế qua thỏa thuận chia nửa Hợp Khí đan."}],"tuViMoc":[],"nhanMach":[{"ten":"Ngô Tính lão giả","tag":"dong-mon","quanHe":"Đồng mưu; Ngô Tính nắm thóp Diệp Tính qua thỏa thuận chia Hợp Khí đan"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0144","c0145","c0146","c0147","c0149","c0150"]},{"id":"ngo-tinh-lao-gia","name":"Ngô Tính lão giả","cn":null,"aliases":["Ngô lão giả","Ngô sư huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Trúc Cơ kỳ (quản sự)","trangThai":"song","blurb":"Quản sự Hoàng Phong Cốc, mũi ưng dài, diện mục âm trầm, nổi danh túc trí đa mưu. Đứng sau bày mưu cho Diệp Tính dụ Hàn Lập nhường Trúc Cơ đan. Thực chất nắm thóp Diệp Tính qua thỏa thuận chia nửa Hợp Khí đan để khống chế lão trong nghị sự tông môn.","vaiTro":"Quản sự Hoàng Phong Cốc; kẻ đứng sau mưu tính","tinhCach":[{"text":"Túc trí đa mưu — bày mưu cho Diệp Tính nhưng thực ra đang gài bẫy để khống chế lão","chuong":144}],"tabs":{"diem":[{"text":"Mũi ưng dài, diện mục âm trầm; nổi danh túc trí đa mưu trong môn phái","chuong":144},{"text":"Khinh thường Hàn Lập: ví bóp chết hắn dễ như bóp con kiến","chuong":150}],"kinhLich":[{"chuong":144,"importance":"normal","tieuDe":"Hiến kế cho Diệp Tính","text":"Gợi ý hỏi rõ thông tin người cầm Thăng Tiên Lệnh. Sau khi biết tư chất ngụy linh căn, xui Diệp Tính dụ người ta tự nguyện nhường đan đổi lấy vật hữu dụng khác."},{"chuong":150,"importance":"normal","tieuDe":"Lộ ý đồ khống chế Diệp Tính","text":"Xuất hiện sau lưng Diệp Tính sau khi Hàn Lập đi. Hai người để lộ đồng mưu. Ngô Tính nắm thóp Diệp Tính qua thỏa thuận chia nửa Hợp Khí đan: sau này nghị sự tông môn Diệp Tính ắt phải nghiêng về phía mình."}],"tuViMoc":[],"nhanMach":[{"ten":"Diệp Tính lão giả","tag":"dong-mon","quanHe":"Đồng mưu; Ngô Tính nắm thóp Diệp Tính để khống chế trong nghị sự"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0144","c0150"]},{"id":"mo-dung-sam","name":"Mộ Dung Sam","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Trúc Cơ kỳ (quản sự)","trangThai":"song","blurb":"Tu sĩ trung niên, quản sự Hoàng Phong Cốc. Vai vế cao — Diệp lão giả phải gọi 'sư huynh' dù trẻ hơn nhiều. Thần tình điềm tĩnh, biện luận sắc bén. Chủ trương giữ lời hứa với Thăng Tiên Lệnh, thách Diệp lão giả phát thề độc.","vaiTro":"Quản sự Hoàng Phong Cốc","tinhCach":[],"tabs":{"diem":[{"text":"Vai vế cao hơn Diệp lão giả dù trẻ hơn nhiều; Diệp phải gọi 'sư huynh'","chuong":144}],"kinhLich":[{"chuong":144,"importance":"normal","tieuDe":"Biện hộ giữ lời hứa Thăng Tiên Lệnh","text":"Giải thích: cả trăm năm mới có người cầm Thăng Tiên Lệnh tới, không thể không cấp đan; thách Diệp lão giả phát thề độc thì mới bỏ qua — Diệp lão giả không dám."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":6,"nguon":["c0144"]},{"id":"vuong-su-thuc","name":"Vương sư thúc","cn":null,"aliases":["Vương sư đệ","Vương dẫn đường","Vương tiên sư"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Trúc Cơ kỳ (quản sự)","trangThai":"song","blurb":"Vương sư thúc là quản sự Trúc Cơ kỳ của Hoàng Phong Cốc, phụ trách dẫn Hàn Lập cùng nhóm đệ tử trúng tuyển từ Thăng Tiên đại hội về cốc. Ông nhiều lần hướng dẫn Hàn Lập trong giai đoạn nhập môn, từ kiểm tra linh căn, phổ biến môn quy đến nhận vật phẩm và làm quen với túi trữ vật. Về sau, ông còn phụ trách báo danh Huyết Cấm Thí Luyện và tham gia chuyển phần thưởng Trúc Cơ đan cho Hàn Lập.","vaiTro":"Quản sự Hoàng Phong Cốc; dẫn đường tại Thăng Tiên đại hội","tinhCach":"hòa nhã; kiên nhẫn; cẩn trọng trước chuyện lạ","tabs":{"diem":[{"text":"Đưa Hàn Lập cùng mười người thắng lôi đài về Hoàng Phong Cốc và kiểm tra thuộc tính linh căn của Hàn Lập.","chuong":"@c0145"},{"text":"Theo phân phó của Chưởng môn, an bài chỗ ở cho Hàn Lập, phổ biến môn quy và giới thiệu kết cấu Hoàng Phong Cốc.","chuong":"@c0147"},{"text":"Dẫn Hàn Lập đi nhận vật phẩm nhập môn và dạy ba điều kiêng kỵ khi dùng túi Thập Bội Trữ Vật.","chuong":"@c0148"},{"text":"Đưa Hàn Lập tới Truyền công các, giới thiệu Ngô Phong làm người chỉ giáo công pháp.","chuong":"@c0149"},{"text":"Phụ trách báo danh Huyết Cấm Thí Luyện và kinh ngạc trước việc Hàn Lập vừa dám dự thí luyện vừa tăng tu vi nhanh.","chuong":"@c0172"},{"text":"Cùng một quản sự khác mang Trúc Cơ đan làm phần thưởng đến cho Hàn Lập và giải thích nguồn gốc phần thưởng.","chuong":"@c0213"}],"kinhLich":[{"chuong":145,"importance":"normal","tieuDe":"Đưa Hàn Lập về cốc — kiểm tra linh căn","text":"Sau khi Hàn Lập nộp Thăng Tiên Lệnh tại Thăng Tiên đại hội, đưa hắn cùng mười người thắng lôi đài về Hoàng Phong Cốc bằng pháp khí hình thuyền; kiểm tra xác định tứ thuộc tính ngụy linh căn."},{"chuong":147,"importance":"normal","tieuDe":"Giới thiệu kết cấu môn phái","text":"Được Chưởng môn phân phó an bài chỗ ở cho Hàn Lập, phổ biến môn quy, giới thiệu toàn bộ kết cấu Hoàng Phong Cốc: ba tầng đệ tử, quản sự, thang tu vi."},{"chuong":148,"importance":"normal","tieuDe":"Dẫn nhận vật phẩm và dạy dùng túi trữ vật","text":"Dẫn Hàn Lập tới nhà Lâm sư đệ nhận vật phẩm; dạy Hàn Lập ba điều kiêng kỵ khi dùng túi Thập Bội Trữ Vật."},{"chuong":149,"importance":"normal","tieuDe":"Giới thiệu Ngô Phong — dẫn đi ra mắt","text":"Dẫn Hàn Lập tới Truyền công các giới thiệu Ngô Phong làm người chỉ giáo công pháp; đưa về khu nhà đá và rời đi sau khi hoàn thành trách nhiệm."},{"chuong":172,"importance":"normal","tieuDe":"Kinh ngạc tu vi tăng vọt của Hàn Lập","text":"Phụ trách báo danh Huyết Cấm Thí Luyện. Kinh ngạc kép: tân nhân như Hàn Lập dám dự thí luyện; và tu vi tăng vọt từ tầng 9 lên tầng 11 — bất thường với ngụy linh căn. Thử lại thuộc tính linh căn vẫn y như cũ, không giải thích được."},{"chuong":173,"importance":"normal","tieuDe":"Tin chuyện Long Lân quả bán tín bán nghi","text":"Bị Hàn Lập bịa chuyện 'Long Lân quả' — loại tiên gia chi quả ghi trong cổ thư 'Kỳ vật dị chí' — thuyết phục. Tra sách xác nhận tên quả đúng, bán tín bán nghi nhưng hoàn tất thủ tục báo danh và dặn dò chú ý cho Hàn Lập."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0144","c0145","c0147","c0148","c0149","c0172","c0173"]},{"id":"lam-su-de","name":"Lâm sư đệ","cn":null,"aliases":["Hôi Y Lão Giả","lão giả áo xám"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Không rõ (trưởng bối)","trangThai":"song","blurb":"Trưởng bối Hoàng Phong Cốc phụ trách phát vật phẩm tùy thân cho đệ tử mới. Áo xám nhàu nát. Tay nghề điêu khắc gỗ cao — khắc khỉ nhỏ sống động chỉ trong một chén trà. Tính lạnh, nói thẳng, bất kính với Chưởng môn Chung Linh Đạo do 'chuyện năm đó'. Lộ tâm sự tịch liêu khi nghe Hàn Lập bỏ qua Trúc Cơ đan.","vaiTro":"Trưởng bối Hoàng Phong Cốc; phát vật phẩm đệ tử mới","tinhCach":[{"text":"Lạnh lùng, nói thẳng, không kiêng nể — chê tư chất Hàn Lập thẳng mặt và mỉa mai Chưởng môn","chuong":148}],"tabs":{"diem":[{"text":"Tay nghề điêu khắc gỗ xuất sắc; sống trong nhà đá rộng hơn bề ngoài (nghi có thủ pháp không gian)","chuong":148},{"text":"Ác cảm với Chưởng môn Chung Linh Đạo do 'chuyện năm đó' — chưa được tiết lộ","chuong":148}],"kinhLich":[{"chuong":148,"importance":"normal","tieuDe":"Phát vật phẩm đệ tử mới cho Hàn Lập","text":"Đang điêu khắc Hoàng Mộc khi Vương sư thúc và Hàn Lập tới; hoàn thành tác phẩm khỉ nhỏ sống động. Chê tư chất Hàn Lập, mỉa mai Chưởng môn. Lấy ra Hoàng ti sam, Thanh Diệp pháp khí, Liệt Dương kiếm, Lãnh Nguyệt đao, Thập Bội Trữ Vật, bộ công cụ tinh luyện giao cho Hàn Lập. Lộ tâm sự tịch liêu khi nghe việc Hàn Lập bỏ qua Trúc Cơ đan."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":6,"nguon":["c0148"]},{"id":"ngo-phong","name":"Ngô Phong","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ — đỉnh điểm (kẹt, không vào được Trúc Cơ kỳ dù đã dùng Trúc Cơ đan)","trangThai":"song","blurb":"Ngô Phong là chấp sự Truyền công các Hoàng Phong Cốc, người phụ trách chỉ giáo công pháp cho Hàn Lập cùng các đệ tử mới. Ông nắm vững pháp thuật sơ cấp, từng giảng giải Hỏa Xà Thuật và các vấn đề liên quan Trúc Cơ đan, nhưng bản thân đã dùng Trúc Cơ đan vẫn kẹt ở đỉnh điểm Luyện Khí kỳ, không vào được Trúc Cơ kỳ.","vaiTro":"Chấp sự Truyền công các Hoàng Phong Cốc","tinhCach":"khiêm nhường; tận tâm chỉ giáo; biết khích lệ hậu bối; giải thích cặn kẽ","tabs":{"diem":[{"text":"Ra mắt tại Truyền công các với vai trò người chỉ giáo công pháp cho Hàn Lập, khiêm nhường đáp lễ dù được đệ tử mới cung kính chào hỏi","chuong":"@c0149"},{"text":"Là một trong số ít người trong cốc còn nhớ hoặc biết Hàn Lập, tiếp tục được Hàn Lập thỉnh giáo công pháp định kỳ","chuong":"@c0152"},{"text":"Giảng Hỏa Xà Thuật sơ cấp bậc trung và khích lệ Hàn Lập khi hắn chán nản về tư chất","chuong":"@c0159"},{"text":"Xác nhận bản thân từng dùng Trúc Cơ đan nhưng vẫn thất bại Trúc Cơ, kẹt ở đỉnh điểm Luyện Khí kỳ","chuong":"@c0159"},{"text":"Giải thích cặn kẽ cho Hàn Lập về xuất xứ chủ dược Trúc Cơ đan và Huyết Cấm Thí Luyện","chuong":"@c0160"},{"text":"Tiết lộ cách phục dụng Trúc Cơ đan: chỉ cần nuốt trực tiếp, không cần thuốc dẫn hay ngoại lực","chuong":"@c0171"}],"kinhLich":[{"chuong":149,"importance":"normal","tieuDe":"Ra mắt làm người chỉ giáo công pháp","text":"Được Vương sư thúc giới thiệu tại Truyền công các. Hàn Lập cung kính chào, Ngô Phong khiêm nhường đáp lễ. Về sau sẽ hướng dẫn công pháp cho Hàn Lập."},{"chuong":152,"importance":"minor","text":"Là một trong số ít người còn nhớ/biết Hàn Lập trong cốc — Hàn Lập thỉnh giáo công pháp định kỳ, học sơ cấp pháp thuật và khẩu quyết từ hắn."},{"chuong":159,"importance":"normal","tieuDe":"Giảng Hỏa Xà Thuật — xác nhận thất bại Trúc Cơ","text":"Giảng Hỏa Xà Thuật sơ cấp bậc trung cho hai thiếu niên. Khi Hàn Lập chán nản về tư chất, khích lệ 'cần cù bù khuyết'. Hàn Lập qua đây biết: Ngô Phong đã dùng Trúc Cơ đan nhưng vẫn kẹt đỉnh Luyện Khí kỳ."},{"chuong":160,"importance":"normal","tieuDe":"Giải thích về Huyết Cấm Thí Luyện","text":"Khi Hàn Lập hỏi về xuất xứ chủ dược Trúc Cơ đan, khuyên bỏ ý định rồi giải thích cặn kẽ: cấm địa phía sau Hoàng Phong Cốc, cơ chế cổ cấm 5 năm/5 ngày, Trúc Cơ kỳ bị chắn ngoài, tỉ lệ sống sót dưới 1/4. Sự kiện Huyết Cấm Thí Luyện diễn ra nửa năm sau."},{"chuong":171,"importance":"normal","tieuDe":"Tiết lộ cách phục dụng Trúc Cơ đan","text":"Hàn Lập hỏi khéo về cách dùng Trúc Cơ đan — chỉ cần nuốt trực tiếp, không cần thuốc dẫn hay ngoại lực, nhưng phải bế quan ba tháng để chuyển hóa hết dược lực; nếu không dược lực đại tán giảm mạnh công hiệu. Câu tiếp theo về 'vấn đề phát sinh sau khi dùng thuốc' khiến Hàn Lập đau đầu."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0149","c0152","c0159","c0160","c0171"]},{"id":"vu-chap-su","name":"Vu chấp sự","cn":null,"aliases":["trung niên chấp sự Bách Ky đường"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ (chấp sự)","trangThai":"song","blurb":"Chấp sự trung niên ở Bách Ky đường Hoàng Phong Cốc. Hằng năm phải nhờ sư huynh đệ hỗ trợ mới tạm hoàn thành nhiệm vụ dược viên khó. Can Hàn Lập đừng chọn nhiệm vụ dược viên Bách Dược Viên. Sau dẫn Hàn Lập tới Kim Phù lĩnh.","vaiTro":"Chấp sự Bách Ky đường Hoàng Phong Cốc","tinhCach":[],"tabs":{"diem":[{"text":"Chấp sự trung niên Bách Ky đường; hằng năm phải nhờ người hỗ trợ mới hoàn thành nhiệm vụ dược viên","chuong":150}],"kinhLich":[{"chuong":149,"importance":"normal","tieuDe":"Kinh ngạc Hàn Lập quay lại xin công tác sớm","text":"Kinh ngạc khi Hàn Lập chưa hết tháng làm quen đã quay lại xin nhận công tác trồng trọt; yêu cầu phải chứng minh kinh nghiệm."},{"chuong":150,"importance":"normal","tieuDe":"Can Hàn Lập — dẫn tới Kim Phù lĩnh","text":"Can ngăn Hàn Lập chọn nhiệm vụ Bách Dược Viên siêu khó. Sau khi Hàn Lập nhận nhiệm vụ, dẫn hắn tới Kim Phù lĩnh."},{"chuong":151,"importance":"minor","text":"Đã quay về Bách Ky đường trước khi Hàn Lập vào Bách Dược Viên — không có mặt lúc bàn giao với Mã sư bá."},{"chuong":152,"importance":"minor","text":"Là một trong số ít người ở cốc còn ngẫu nhiên nhớ tới Hàn Lập; mỗi tháng phát linh thạch cho hắn tại Bách Ky đường."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":7,"nguon":["c0149","c0150","c0151","c0152"]},{"id":"ma-su-ba","name":"Mã sư bá","cn":null,"aliases":["Mã lão giả","lão đầu"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Tu tiên (cảnh giới không rõ — cao hơn Hàn Lập, phi hành tự do)","trangThai":"song","blurb":"Mã sư bá là lão giả tu tiên cao hơn Hàn Lập, chủ nhân thật sự của Bách Dược Viên tại Kim Phù lĩnh và là trưởng bối trong Hoàng Phong Cốc. Lão giao việc trông coi dược viên cho Hàn Lập sau khi thử khả năng nhận biết thảo dược, về sau nhiều lần hỗ trợ hoặc trao đổi lợi ích với hắn quanh dược viên, đan dược và việc vào Nhạc Lộc điện.","vaiTro":"Trưởng bối Hoàng Phong Cốc; chủ nhân Bách Dược Viên","tinhCach":"thẳng thắn, không khách khí; coi trọng dược lý; có phần cổ quái; biết giữ lợi ích khi giao dịch","tabs":{"diem":[{"text":"Thử Hàn Lập nhận mặt thảo dược, kinh ngạc khi hắn gọi đúng nhiều loại hiếm và giao quyền quản lý Bách Dược Viên.","chuong":"@c0151"},{"text":"Hài lòng với việc Hàn Lập trông coi Bách Dược Viên, tăng thưởng linh thạch từ 2 lên 5 khối.","chuong":"@c0152"},{"text":"Cấp ngọc phù giúp Hàn Lập vào Nhạc Lộc điện, đổi bằng một năm trông coi dược viên miễn phí.","chuong":"@c0153"},{"text":"Lỡ miệng tiết lộ ba chủ dược của Trúc Cơ đan là Ngọc Tủy Chi, Tử Hầu Hoa và Thiên Linh Quả.","chuong":"@c0159"},{"text":"Tặng Hàn Lập hai bình đan dược khi nghe hắn chuẩn bị tham gia Huyết Cấm Thí Luyện.","chuong":"@c0173"},{"text":"Tại Bách Dược Viên, cảm ứng được biến hóa cảnh giới của Hàn Lập khi gọi tên hắn.","chuong":"@c0217"}],"kinhLich":[{"chuong":151,"importance":"major","tieuDe":"Bàn giao Bách Dược Viên cho Hàn Lập","text":"Thử thách Hàn Lập nhận mặt thảo dược — kinh ngạc khi hắn gọi đúng nhiều loại hiếm. Giao quyền quản lý dược viên + mộc bài mộc xanh; để lại bút ký kinh nghiệm + thảo dược tâm đắc. Bay đi để chuyên tâm tu hành/luyện đan."},{"chuong":152,"importance":"minor","text":"Mỗi kỳ tới Bách Dược Viên nhận dược liệu đều hài lòng với Hàn Lập; tăng thưởng linh thạch từ 2 lên 5 khối/tháng."},{"chuong":153,"importance":"minor","text":"Cấp ngọc phù bảo đảm cho Hàn Lập vào Nhạc Lộc điện — đổi bằng một năm trông coi dược viên miễn phí."},{"chuong":159,"importance":"normal","tieuDe":"Tiết lộ bí mật ba chủ dược Trúc Cơ đan","text":"Bị Hàn Lập khích, lỡ miệng tiết lộ: Ngọc Tủy Chi, Tử Hầu Hoa, Thiên Linh Quả không có hạt giống, do thiên địa linh khí sinh ra, không thể nuôi trồng. Nơi tìm được 'cùng với tự sát không kém bao nhiêu'. Hẹn hai tháng sau quay lại lấy thuốc rồi bay đi."},{"chuong":173,"importance":"normal","tieuDe":"Tặng hai bình đan dược cho Hàn Lập","text":"Nghe Hàn Lập nhờ tạm gánh việc dược viên để chuẩn bị Huyết Cấm Thí Luyện, nửa ngày không nói — nhìn Hàn Lập bằng ánh mắt 'ngươi nhất định chết'. Trước khi rời đi bất ngờ ném cho Hàn Lập hai bình đan dược: một bình uống vào, một bình xoa ngoài da — hành động của người diện lãnh tâm nhiệt."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0151","c0152","c0153","c0159","c0173"]},{"id":"hua-lao","name":"Hứa lão","cn":null,"aliases":["Hứa bá","lão giả gian thương"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Tu tiên (cảnh giới không rõ — Thiên Nhãn Thuật của Hàn Lập không soi được, ít nhất Trúc Cơ kỳ)","trangThai":"song","blurb":"Lão giả mặt đầy hồng quang, trông coi tàng thư thông đạo 'Đan' tại Nhạc Lộc điện. Bản chất là gian thương thế tục không phải tu sĩ Trúc Cơ kỳ — cố ý bảo người gọi 'Hứa lão' chứ không xưng 'sư bá' để tiện thu phí. Thợ luyện chế đan lô pháp khí, phần lớn đỉnh lô đệ tử cấp thấp Hoàng Phong Cốc đều do lão làm. Tham linh thạch, hay gài 'miễn phí' để bán hàng, nhưng không bịa đặt về kiến thức địa hỏa.","vaiTro":"Người trông coi tàng thư đan phương và bán đan lô tại Nhạc Lộc điện","tinhCach":[{"text":"Tham tài, gian thương điển hình: phí đọc sách 1 linh thạch/canh giờ, phí phục chế ngọc đồng 10 linh thạch/lần — cắt cổ với đệ tử cấp thấp","chuong":154},{"text":"Hay dùng chiêu 'miễn phí' để gài mua hàng; kiểm tiền nhiều lần khi nhận; mau lẹ khi phục chế","chuong":155}],"tabs":{"diem":[{"text":"Mặt đầy hồng quang, cười hì hì; sở hữu túi vải trữ vật dung lượng cực lớn","chuong":154},{"text":"Không phải tu sĩ Trúc Cơ kỳ — là 'gian thương phàm nhân' ở thế tục vào nơi đây","chuong":155}],"kinhLich":[{"chuong":154,"importance":"normal","tieuDe":"Gặp Hàn Lập lần đầu tại Nhạc Lộc điện","text":"Chủ động chào Hàn Lập; từ chối xưng 'sư bá'. Mở cầu thang lên lầu hai bằng lệnh bài, đặt phí đọc sách (1 linh thạch/canh giờ) và phí sao chép (10 linh thạch/lần); Hàn Lập trả tổng 2 linh thạch."},{"chuong":155,"importance":"normal","tieuDe":"Phục chế hai ngọc đồng đan phương","text":"Bị Hàn Lập dùng chiêu 'chỉ phục chế một cái' để moi câu hỏi miễn phí, sau đó nhận 20 linh thạch phục chế cả hai ngọc đồng. Giải thích lý do thất truyền đan phương trong tu tiên giới do đại kiếp và nguyên liệu cạn dần."},{"chuong":156,"importance":"normal","tieuDe":"Tiết lộ địa phế chi hỏa — bán Ngân Ti đỉnh","text":"Buột miệng khoe đan lô chịu nhiệt địa hỏa, vô tình mở lối thoát cho Hàn Lập đang bế tắc chuyện tiên thiên chân hỏa. Giải thích kiến thức địa phế chi hỏa và huyền dương hỏa địa. Bán Ngân Ti đỉnh giá 32 linh thạch sau khi Hàn Lập mặc cả; tổng thu 50 linh thạch từ Hàn Lập."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0154","c0155","c0156"]},{"id":"mo-dung-huyen-de","name":"Mộ Dung huynh đệ","cn":null,"aliases":["hai huynh đệ họ Mộ Dung","song sinh Mộ Dung"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ (đệ tử mới, chưa tầng 9)","trangThai":"song","blurb":"Hai huynh đệ sinh đôi đệ tử mới nhập môn Hoàng Phong Cốc, khoảng 21-22 tuổi, mi thanh mục tú, da trắng nõn, ánh mắt nghịch ngợm. Sở hữu dị linh căn chuyển hóa thành lôi linh căn — tư chất nổi bật nhất đợt thu đệ tử, được trưởng lão Kết Đan kỳ hứa thu làm môn hạ nếu Trúc Cơ thành công. Thông thạo lôi hệ pháp thuật gồm Chưởng tâm lôi và liên hoàn lôi thuật trung cấp Thiên lôi liên hoàn kích.","vaiTro":"Đệ tử mới Hoàng Phong Cốc; sư đệ của Niếp sư muội","tinhCach":[{"text":"Hưng phấn biểu diễn, nghịch ngợm, dễ nổi khí; bị khích là tức giận đến trắng mặt nhận ngay thách đấu","chuong":157}],"tabs":{"diem":[{"text":"Song sinh, khoảng 21-22 tuổi; từ dị linh căn chuyển hóa thành lôi linh căn — tư chất hiếm có trong cốc","chuong":152},{"text":"Trưởng lão Kết Đan kỳ phá lệ xuất quan để quan sát, hứa thu làm môn hạ nếu Trúc Cơ thành công","chuong":152}],"kinhLich":[{"chuong":152,"importance":"normal","tieuDe":"Nhập môn Hoàng Phong Cốc","text":"Là điểm sáng của đợt thu đệ tử với lôi linh căn từ dị linh căn chuyển hóa; trưởng lão Kết Đan kỳ đặc cách hứa thu làm môn hạ."},{"chuong":157,"importance":"normal","tieuDe":"Tỷ thí với Lục sư huynh — đuối pháp lực","text":"Biểu diễn Chưởng tâm lôi, sau đó bị Lục sư huynh (phong linh căn) khinh thường thách đấu. Thi triển Thiên lôi liên hoàn kích — đám mây đen lớn, thiểm điện liên tục; vòng bảo hộ của Lục sư huynh suýt bị nghiền nát. Cuối cùng do đã tiêu hao pháp lực khi biểu diễn trước đó và tu luyện còn non, pháp lực kiệt sức trước, đành thua."},{"chuong":158,"importance":"normal","tieuDe":"Bị Niếp sư muội phạt diện bích","text":"Khi Lục sư huynh thi triển Thanh Hồ trảm áp chế, một người mượn người ngoài làm khiên, một người mượn Hàn Lập (nhưng bị hắn né). Được Niếp sư muội giải vây; bị phạt diện bích cho tới khi luyện thành công pháp tầng thứ chín."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":6,"nguon":["c0152","c0157","c0158"]},{"id":"luc-su-huynh","name":"Lục sư huynh","cn":null,"aliases":["Lục Tính thanh niên"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"da-roi"}],"canhGioiCaoNhat":"Luyện Khí kỳ tầng 12 trung giai — phong linh căn","trangThai":"tu-vong","blurb":"Lục sư huynh là đệ tử Hoàng Phong Cốc, mang phong linh căn, tu vi cao nhất được xác nhận là Luyện Khí kỳ tầng 12 trung giai. Hắn từng thách đấu Mộ Dung huynh đệ, cưỡng bức Trần sư muội và mưu đoạt Trúc Cơ đan, sau đó chết trong ác đấu với Hàn Lập.","vaiTro":"Đệ tử Hoàng Phong Cốc; đối thủ của Hàn Lập","tinhCach":"ngạo mạn khinh địch; tham lam vụ lợi; thủ đoạn tàn nhẫn","tabs":{"diem":[{"text":"Khinh thường lôi linh căn, thách đấu Mộ Dung huynh đệ trong điều kiện không tránh né và không dùng pháp khí","chuong":"@c0157"},{"text":"Dùng Thanh Hồ trảm phản công khi Mộ Dung huynh đệ kiệt pháp lực, nhưng bị Niếp sư muội dừng tay","chuong":"@c0158"},{"text":"Dùng Hợp Hoan Hoàn cưỡng bức Trần sư muội và phát hiện hộp chứa bình xanh đựng Trúc Cơ đan","chuong":"@c0165"},{"text":"Lộ tu vi Luyện Khí kỳ tầng 12 trung giai cùng phong linh căn, đồng thời bộc lộ ý đồ mưu đoạt Trúc Cơ đan","chuong":"@c0166"},{"text":"Dùng Phong tường thuật, Thanh giao kỳ và đao phong trong ác đấu với Hàn Lập rồi tử vong","chuong":"@c0169"},{"text":"Từng được Hàn Lập hồi tưởng là người dùng thượng phẩm pháp khí Thanh giao kỳ giằng co với phù bảo phi kiếm","chuong":"@c0188"}],"kinhLich":[{"chuong":157,"importance":"normal","tieuDe":"Thách đấu Mộ Dung huynh đệ","text":"Khinh thường lôi linh căn, thách đấu không tránh né không dùng pháp khí. Dùng vòng hào quang bảo hộ chịu đòn Thiên lôi liên hoàn kích; kinh ngạc trước uy lực vượt dự tính. Cuối cùng thắng nhờ pháp lực tinh thuần thâm hậu hơn do tu luyện nhiều năm."},{"chuong":158,"importance":"normal","tieuDe":"Thanh Hồ trảm — bị Niếp sư muội dừng tay","text":"Phản công bằng Thanh Hồ trảm khi Mộ Dung huynh đệ kiệt pháp lực; tách đạo quang làm đôi truy hai hướng. Bị Niếp sư muội ngọn lửa thiêu nuốt Thanh Hồ, đổi thái độ lễ độ ngay. Lúc rời đi lóe tia ác ý nhìn thanh niên thấp lùn mang mộc quải, trừng mắt đe dọa."},{"chuong":165,"importance":"normal","tieuDe":"Cưỡng bức Trần sư muội — phát hiện Trúc Cơ đan","text":"Dùng Hợp Hoan Hoàn cưỡng bức Trần sư muội; tìm thấy hộp gỗ đỏ bí ẩn trong đồ vật của nàng chứa bình xanh đựng 2 viên Trúc Cơ đan thật. Hàn Lập tình cờ chứng kiến."},{"chuong":166,"importance":"normal","tieuDe":"Lộ thân phận — mưu đoạt Trúc Cơ đan","text":"Lộ cảnh giới thật: Luyện Khí tầng 12 trung giai, phong linh căn. Tiết lộ động cơ: nhà họ Đổng hứa gả con gái nếu được song tu kinh; cần Trúc Cơ đan làm mồi nhử. Dàn trận tấn công Hàn Lập."},{"chuong":169,"importance":"major","tieuDe":"Chết trong ác đấu với Hàn Lập","text":"Chiến đấu quyết liệt c167–c169 với Hàn Lập: dùng Phong tường thuật, Thanh giao kỳ (Hóa giao), đao phong. Liều chết thu pháp lực Thanh giao kỳ dồn đao phong lớn nhưng thất bại — bị cự kiếm của Hàn Lập chém bửa làm đôi, chết. Túi trữ vật với 2 viên Trúc Cơ đan bị Hàn Lập thu."}],"tuViMoc":[{"chuong":166,"canhGioi":"Luyện Khí kỳ tầng 12 trung giai — phong linh căn","text":"Xác nhận qua tự tiết lộ và điều khiển Thanh giao kỳ trong trận. Pháp lực thâm hậu hơn Hàn Lập (tầng 11) rõ rệt.","importance":"normal"}],"nhanMach":[{"ten":"Trần sư muội","tag":"tinh-nhan","quanHe":"Tình lữ (bị hắn hại)"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":6,"nguon":["c0157","c0158","c0165","c0166","c0167","c0168","c0169"]},{"id":"niep-su-muoi","name":"Niếp sư muội","cn":null,"aliases":["lam y nữ tử","nữ tử áo lam"],"gioiTinh":"nu","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Tu tiên (cảnh giới cao hơn Lục sư huynh và Mộ Dung huynh đệ rõ rệt)","trangThai":"song","blurb":"Niếp sư muội là nữ đệ tử Hoàng Phong Cốc, được biết đến với hình tượng nữ tử áo lam dung mạo xuất trần và pháp lực cao hơn rõ rệt so với Lục sư huynh cùng Mộ Dung huynh đệ. Nàng từng ra tay từ trên không chấm dứt cuộc tỷ thí, áp chế Thanh Hồ trảm của Lục sư huynh và xử phạt Mộ Dung huynh đệ.","vaiTro":"Đệ tử Hoàng Phong Cốc; sư tỷ Mộ Dung huynh đệ","tinhCach":"lạnh nhạt; nghiêm khắc với đồng môn; chủ động khiển trách việc né tránh cứu người","tabs":{"diem":[{"text":"Từ trên không phóng ngọn lửa nuốt trọn Thanh Hồ trảm của Lục sư huynh","chuong":"@c0158"},{"text":"Xuất hiện chấm dứt cuộc tỷ thí","chuong":"@c0158"},{"text":"Xử phạt Mộ Dung huynh đệ diện bích","chuong":"@c0158"}],"kinhLich":[{"chuong":158,"importance":"major","tieuDe":"Xuất hiện chấm dứt cuộc tỷ thí — phạt Mộ Dung huynh đệ","text":"Từ trên không phóng ngọn lửa nuốt Thanh Hồ trảm của Lục sư huynh. Phạt Mộ Dung huynh đệ diện bích cho tới khi luyện thành công pháp tầng thứ chín. Truyền âm riêng khiển trách Hàn Lập về hành động né tránh không cứu người, mong hắn 'lần sau gặp lại có thay đổi'."}],"tuViMoc":[],"nhanMach":[{"ten":"Mộ Dung huynh đệ","tag":"su-mon","quanHe":"Sư muội — sư tỷ của hai huynh đệ họ Mộ Dung"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0158"]},{"id":"tran-su-muoi","name":"Trần sư muội","cn":null,"aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ trung tầng 12","trangThai":"song","blurb":"Nữ tử diễm lệ, con gái gia chủ Trần gia và đệ tử Hoàng Phong Cốc, tu vi Luyện Khí kỳ trung tầng 12. Nàng trúng Hợp Hoan đan của Lục sư huynh và bị cưỡng bức, sau được Hàn Lập giải độc bằng Thanh Linh Tán rồi an trí trong hang bí mật. Sau biến cố tính tình thay đổi hẳn, không nhớ mặt Hàn Lập, tự tham gia Huyết Cấm Thí Luyện, và về sau phục dụng Trúc cơ đan để đột phá thành công lên Trúc Cơ kỳ.","vaiTro":"Đệ tử Hoàng Phong Cốc; con gái gia chủ Trần gia; nạn nhân kế hoạch của Lục sư huynh","tinhCach":"Si tình và chiếm hữu với Lục sư huynh; nhiều lo âu, hay can ngăn; sau biến cố trở nên lãnh diễm cự người; quật cường, quyết tâm tìm lại thứ đã mất","tabs":{"diem":[{"text":"Trúng Hợp Hoan đan của Lục sư huynh và bị cưỡng bức, mất ý thức tự chủ","chuong":"@c0165"},{"text":"Được Hàn Lập ẵm bay hơn trăm dặm, an trí trong hang bí mật và nhét cho Thanh Linh Tán giải độc","chuong":"@c0171"},{"text":"Xuất hiện trong đoàn đệ tử Hoàng Phong Cốc dự Huyết Cấm Thí Luyện với tu vi trung tầng 12, cao hơn Hàn Lập","chuong":"@c0173"},{"text":"Dùng hai phi kiếm lam-vàng tranh đoạt linh thảo trong cấm địa dù thực lực yếu nhất","chuong":"@c0199"},{"text":"Tỏ thái độ khinh bỉ Hàn Lập khi ra khỏi cấm địa","chuong":"@c0209"},{"text":"Phục dụng Trúc cơ đan phần thưởng, khổ tu và đột phá thành công lên Trúc Cơ kỳ","chuong":"@c0213"}],"kinhLich":[{"chuong":157,"importance":"minor","text":"Có mặt bên cạnh Lục sư huynh khi hắn thách đấu Mộ Dung huynh đệ; lo lắng can ngăn nhưng bị từ chối."},{"chuong":158,"importance":"minor","text":"Sợ Lục sư huynh bị Niếp sư muội mê hoặc; chủ động quàng tay hắn, dùng ánh mắt thù địch nhìn nữ tử áo lam."},{"chuong":165,"importance":"normal","tieuDe":"Trúng Hợp Hoan đan — bị Lục sư huynh cưỡng bức","text":"Trúng Hợp Hoan đan của Lục sư huynh, mất ý thức tự chủ. Trong đồ vật của nàng có hộp gỗ đỏ chứa bình xanh đựng 2 viên Trúc Cơ đan thật — vật Lục sư huynh muốn chiếm đoạt. Hàn Lập tình cờ chứng kiến."},{"chuong":170,"importance":"minor","text":"Trong trạng thái Hợp Hoan đan, nàng tấn công Hàn Lập sau khi hắn hạ Lục sư huynh. Hàn Lập dùng Định thần phù / Định Thần thuật khống chế, đưa nàng đến nơi an toàn."},{"bridge":true,"khoang":"c0171","text":"Hàn Lập ẵm nàng bay về phía Tây hơn trăm dặm, đặt trong hang bí mật. Trước khi đi nhét cho nàng Thanh Linh Tán để giải dâm độc Hợp Hoan đan. Nàng tỉnh dậy không nhớ gì."},{"chuong":173,"importance":"normal","tieuDe":"Xuất hiện trong đoàn dự Huyết Cấm Thí Luyện","text":"Xuất hiện trong đoàn đệ tử Hoàng Phong cốc dự Huyết Cấm Thí Luyện. Tu vi trung tầng 12 — cao hơn Hàn Lập (tầng 11). Sau biến cố lãnh diễm khác hẳn xưa, không tô điểm, thần thái cự người, không nhận ra Hàn Lập do mê huyễn lực Hợp Hoan đan. Tham gia vì mất Trúc Cơ đan, muốn tự tìm trong cấm địa."},{"chuong":175,"importance":"minor","text":"Tụ tập cùng một nữ tử khác, được vài nam đệ tử bắt chuyện. Sáng hôm sau đứng ngay cạnh Hàn Lập chờ các phái — mùi hương quen thuộc gợi hắn nhớ đêm cũ, khiến hắn mất tự nhiên."},{"chuong":178,"importance":"minor","text":"Hai má ửng hồng, nắm chặt quyền, đầy quyết tâm nghe Lý sư tổ giảng về sinh tử chiến trong cấm địa."}],"tuViMoc":[{"chuong":173,"canhGioi":"Luyện Khí kỳ trung tầng 12","text":"Xác nhận qua quan sát của Hàn Lập khi đánh giá toàn đoàn trước Huyết Cấm Thí Luyện.","importance":"normal"}],"nhanMach":[{"ten":"Lục sư huynh","tag":"tinh-nhan","quanHe":"Tình lang cũ (người đã hại nàng)"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":7,"nguon":["c0157","c0158","c0165","c0166","c0170","c0171","c0173","c0175","c0178"]},{"id":"dien-bac-ly","name":"Điền Bặc Ly","cn":null,"aliases":["chưởng quỹ Vạn Bảo Lâu"],"gioiTinh":"nam","theLuc":[{"ten":"Vạn Bảo Lâu","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Người thường (phàm nhân)","trangThai":"song","blurb":"Chưởng quỹ phường thị Vạn Bảo Lâu tại phường thị Hoàng Phong Cốc. Người thường, am hiểu vật phẩm tu tiên, giải thích rõ ràng cơ chế phòng thủ hộp gấm và nguyên lý phù bảo. Tiếp đón Hàn Lập khi hắn tới mua vật phẩm chuẩn bị Huyết Cấm Thí Luyện.","vaiTro":"Chưởng quỹ Vạn Bảo Lâu","tinhCach":[],"tabs":{"diem":[{"text":"Người thường nhưng am hiểu đạo lý vật phẩm tu tiên — trình bày mạch lạc cơ chế phòng thủ hộp gấm và phù bảo","chuong":162}],"kinhLich":[{"chuong":162,"importance":"normal","text":"Tiếp Hàn Lập tại Vạn Bảo Lâu; giải thích cơ chế phòng thủ hai luồng pháp lực khi mở hộp gấm — an toàn với Trúc Cơ kỳ trở lên."},{"chuong":164,"importance":"minor","text":"Giải thích cơ chế phù bảo: Kết Đan kỳ luyện chế; tiền-Trúc-Cơ phát huy 1–2 thành; hậu Trúc Cơ phát huy toàn bộ; số lần hữu hạn."},{"chuong":165,"importance":"minor","text":"Chứng kiến Hàn Lập dùng 2 gốc linh thảo ngàn năm đổi toàn bộ hộp gấm, hoàn tất giao dịch."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":9,"nguon":["c0162","c0163","c0164","c0165"]},{"id":"dinh-lao","name":"Đinh lão","cn":null,"aliases":["giám định dược Vạn Bảo Lâu"],"gioiTinh":"nam","theLuc":[{"ten":"Vạn Bảo Lâu","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Người thường (phàm nhân)","trangThai":"song","blurb":"Lão giả giám định dược vật tại Vạn Bảo Lâu, người thường. Am hiểu linh thảo tu tiên, xác nhận chính xác Hoàng tinh chi là thật và tuổi hơn ngàn năm. Được Điền Bặc Ly triệu đến khi Hàn Lập yêu cầu giám định.","vaiTro":"Giám định dược Vạn Bảo Lâu","tinhCach":[],"tabs":{"diem":[{"text":"Người thường am hiểu linh thảo — xác nhận chính xác Hoàng tinh chi thật, tuổi hơn ngàn năm","chuong":164}],"kinhLich":[{"chuong":163,"importance":"minor","text":"Được triệu đến giám định Hoàng tinh chi do Hàn Lập yêu cầu."},{"chuong":164,"importance":"minor","text":"Xác nhận Hoàng tinh chi là thật, tuổi hơn ngàn năm — giao dịch được chốt."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":10,"nguon":["c0163","c0164"]},{"id":"co-gai-linh-thu-son","name":"Nữ đệ tử Linh Thú Sơn (cô gái bán Kim Trúc Bút)","cn":null,"aliases":["cô gái bán Kim Trúc Bút","thiếu nữ Thái Nam hội"],"gioiTinh":"nu","theLuc":[{"ten":"Linh thú sơn","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Luyện Khí kỳ (đệ tử Linh Thú Sơn)","trangThai":"song","blurb":"Nữ đệ tử Linh Thú Sơn tham gia Huyết Cấm Thí Luyện. Trước đây từng bán Kim Trúc Bút cho Hàn Lập tại Thái Nam hội. Gương mặt tú lệ, tính thẹn thùng hay đỏ mặt. Trong đoàn Linh Thú Sơn bị gã râu quai nón và đồng môn ức hiếp, khinh bỉ. Chưa nêu tên trong nguyên tác.","vaiTro":"Đệ tử Linh Thú Sơn; nhân vật quen cũ của Hàn Lập","tinhCach":[{"text":"Thẹn thùng, hay đỏ mặt — cúi đầu khi Hàn Lập mỉm cười, phản ứng tự nhiên không phải giả tạo","chuong":179}],"tabs":{"diem":[{"text":"Gương mặt tú lệ quen thuộc, xinh đẹp hơn trước, vẫn dáng thẹn thùng hay đỏ mặt như hồi Thái Nam hội","chuong":179}],"kinhLich":[{"chuong":137,"importance":"minor","text":"Gặp Hàn Lập tại Thái Nam hội, bán Kim Trúc Bút (di vật gia tộc) để đổi đan dược giúp huynh trưởng đột phá dự lôi đài."},{"chuong":179,"importance":"normal","tieuDe":"Gặp lại Hàn Lập trước cửa cấm địa","text":"Nhận ra Hàn Lập, nhìn chăm chú. Hàn Lập nhận ra nàng, mỉm cười — nàng đỏ mặt cúi đầu. Gã râu quai nón đứng sau nạt nộ và cảnh cáo bằng ánh mắt ác độc; nàng tái mặt cúi đầu không dám nhìn sang. Hàn Lập đoán nàng thường bị ức hiếp."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":8,"nguon":["c0137","c0179"]}]};
